func _build_worker_units() -> Array[Dictionary]:
	var units: Array[Dictionary] = []
	var extras: Array = []
	var party_source: Array = worker_party
	if not Engine.is_editor_hint() and GameEvents.has_method("get_worker_party"):
		party_source = GameEvents.get_worker_party()
	for actor in party_source:
		if actor == null:
			continue
		extras.append(actor)
		if extras.size() >= max(_desired_worker_count - 1, 0):
			break
	if units.size() < _desired_worker_count:
		var lead_actor: BattleActor = leader_actor
		if lead_actor == null and Engine.is_editor_hint():
			lead_actor = _make_preview_actor("Leader")
		if lead_actor:
			units.append(_create_unit(lead_actor, _leader_marker, "worker", 0))
	var slot_index := 0
	for actor in extras:
		if units.size() >= _desired_worker_count:
			break
		var marker := _ally_markers[slot_index] if slot_index < _ally_markers.size() else null
		units.append(_create_unit(actor, marker, "worker", units.size()))
		slot_index += 1

	if Engine.is_editor_hint():
		while units.size() < _desired_worker_count:
			var marker := _ally_markers[slot_index] if slot_index < _ally_markers.size() else null
			if marker == null:
				break
			units.append(_create_unit(_make_preview_actor("Worker %d" % (units.size() + 1)), marker, "worker", units.size()))
			slot_index += 1
	return units

func _build_enemy_units() -> Array[Dictionary]:
	var units: Array[Dictionary] = []
	var actors: Array = _get_enemy_battle_actors()
	var slot_index := 0
	for actor in actors:
		if actor == null:
			continue
		if slot_index >= _enemy_markers.size() or slot_index >= _desired_enemy_count:
			break
		var marker := _enemy_markers[slot_index]
		units.append(_create_unit(actor, marker, "enemy", slot_index))
		slot_index += 1

	if Engine.is_editor_hint() and _battle_enemy_node == null:
		while units.size() < _desired_enemy_count and slot_index < _enemy_markers.size():
			var marker := _enemy_markers[slot_index]
			units.append(_create_unit(_make_preview_actor("Enemy %d" % (slot_index + 1)), marker, "enemy", slot_index))
			slot_index += 1
	return units

func _apply_layouts() -> void:
	var worker_markers := _get_layout_markers(worker_layout_root, _worker_units.size(), false)
	if worker_markers.size() > 0:
		_apply_markers_to_units(_worker_units, worker_markers)
	else:
		_apply_layout_to_units(_worker_units, _get_worker_layout(_worker_units.size()))
	var enemy_markers := _get_layout_markers(enemy_layout_root, _enemy_units.size(), false)
	if enemy_markers.size() > 0:
		_apply_markers_to_units(_enemy_units, enemy_markers)
	else:
		_apply_layout_to_units(_enemy_units, _get_enemy_layout(_enemy_units.size()))
	_refresh_battle_unit_draw_order()

func _apply_layout_to_units(units: Array, layout: PackedVector2Array) -> void:
	if layout.is_empty():
		return
	for i in range(min(units.size(), layout.size())):
		var marker: Marker2D = units[i].get("marker")
		if marker:
			marker.position = layout[i]

func _apply_markers_to_units(units: Array, markers: Array[Marker2D]) -> void:
	for i in range(min(units.size(), markers.size())):
		units[i]["marker"] = markers[i]

func _get_worker_layout(count: int) -> PackedVector2Array:
	var from_nodes := _get_layout_from_nodes(worker_layout_root, count, false)
	if not from_nodes.is_empty():
		return from_nodes
	match count:
		1:
			return worker_layout_1
		2:
			return worker_layout_2
		3:
			return worker_layout_3
		4:
			return worker_layout_4
		_:
			return worker_layout_4

func _get_enemy_layout(count: int) -> PackedVector2Array:
	var from_nodes := _get_layout_from_nodes(enemy_layout_root, count, false)
	if not from_nodes.is_empty():
		return from_nodes
	match count:
		1:
			return enemy_layout_1
		2:
			return enemy_layout_2
		3:
			return enemy_layout_3
		4:
			return enemy_layout_4
		_:
			return enemy_layout_4

func _get_desired_worker_count() -> int:
	if Engine.is_editor_hint():
		return clampi(preview_worker_count, 1, 4)
	var worker_count: int = 0
	if GameEvents.has_method("get_worker_party"):
		worker_count = GameEvents.get_worker_party().size()
	else:
		worker_count = worker_party.size()
	var leader_count: int = 1 if leader_actor != null else 0
	return clampi(leader_count + worker_count, 1, 4)


func _get_desired_enemy_count() -> int:
	if Engine.is_editor_hint() and _battle_enemy_node == null:
		return clampi(preview_enemy_count, 1, 4)
	var actors: Array = _get_enemy_battle_actors()
	var derived_count: int = actors.size()
	# When a world enemy explicitly provides its battle actors, that list is the
	# source of truth. The legacy metadata flag is only a fallback for old scenes.
	if derived_count > 0:
		return clampi(derived_count, 1, 4)
	if _battle_enemy_node != null and _battle_enemy_node.has_meta("battle_party_size"):
		var requested: int = clampi(int(_battle_enemy_node.get_meta("battle_party_size")), 1, 4)
		return requested
	return 1


func _get_enemy_battle_actors() -> Array:
	var actors: Array = []
	if _battle_enemy_node != null:
		var node_leader_v: Variant = _battle_enemy_node.get("battle_leader_actor")
		if node_leader_v is BattleActor:
			_append_unique_actor(actors, node_leader_v as BattleActor)
		elif enemy_actor != null:
			_append_unique_actor(actors, enemy_actor)
		var node_party_v: Variant = _battle_enemy_node.get("battle_extra_party")
		if node_party_v is Array:
			for a in node_party_v:
				if a is BattleActor:
					actors.append(a as BattleActor)
		return actors

	var leader: BattleActor = enemy_actor
	if leader == null:
		if Engine.is_editor_hint():
			leader = _make_preview_actor("Enemy")
		else:
			var fallback := load("res://Resources/enemy_actor.tres")
			if fallback is BattleActor:
				leader = fallback
	_append_unique_actor(actors, leader)

	var party_source: Array = enemy_party
	if not Engine.is_editor_hint() and GameEvents.has_method("get_enemy_party"):
		var global_party: Array = GameEvents.get_enemy_party()
		if global_party.size() > 0:
			party_source = global_party
	for actor in party_source:
		if actor is BattleActor:
			actors.append(actor as BattleActor)
	return actors


func _append_unique_actor(target: Array, actor: BattleActor) -> void:
	if actor == null:
		return
	if target.has(actor):
		return
	target.append(actor)

func _get_layout_from_nodes(root_path: NodePath, count: int, leader_last: bool) -> PackedVector2Array:
	var root := get_node_or_null(root_path) as Node
	if root == null:
		return PackedVector2Array()
	var layout_node := root.get_node_or_null("Layout%d" % count)
	if layout_node == null:
		return PackedVector2Array()
	var names := _get_layout_marker_names(count, leader_last)
	var result: PackedVector2Array = PackedVector2Array()
	for name in names:
		var marker := layout_node.get_node_or_null(name) as Marker2D
		if marker:
			result.append(marker.position)
	return result

func _get_layout_markers(root_path: NodePath, count: int, leader_last: bool) -> Array[Marker2D]:
	var root := get_node_or_null(root_path) as Node
	if root == null:
		return []
	var layout_node := root.get_node_or_null("Layout%d" % count)
	if layout_node == null:
		return []
	var names := _get_layout_marker_names(count, leader_last)
	var result: Array[Marker2D] = []
	for name in names:
		var marker := layout_node.get_node_or_null(name) as Marker2D
		if marker:
			result.append(marker)
	return result

func _get_layout_marker_names(count: int, leader_last: bool) -> Array[String]:
	if leader_last:
		match count:
			1:
				return ["Marker4"]
			2:
				return ["Marker1", "Marker4"]
			3:
				return ["Marker1", "Marker2", "Marker4"]
			_:
				return ["Marker1", "Marker2", "Marker3", "Marker4"]
	match count:
		1:
			return ["Marker1"]
		2:
			return ["Marker1", "Marker2"]
		3:
			return ["Marker1", "Marker2", "Marker3"]
		_:
			return ["Marker1", "Marker2", "Marker3", "Marker4"]

func _create_unit(actor: BattleActor, marker: Marker2D, side: String, index: int) -> Dictionary:
	var max_hp_value: int = maxi(actor.max_hp, 1) if actor else 1
	var current_hp_value: int = max_hp_value
	if side == "worker" and not Engine.is_editor_hint() and actor != null and GameEvents.has_method("get_actor_state"):
		var state: Dictionary = GameEvents.get_actor_state(actor)
		if not state.is_empty():
			max_hp_value = maxi(int(state.get("max_hp", max_hp_value)), 1)
			current_hp_value = clampi(int(state.get("hp", max_hp_value)), 0, max_hp_value)
	var unit: Dictionary = {
		"uid": _next_battle_unit_uid,
		"actor": actor,
		"hp": current_hp_value,
		"max_hp": max_hp_value,
		"shield": 0,
		"progress": 0.0,
		"side": side,
		"index": index,
		"marker": marker,
		"view": null,
		"sprite": null,
		"aim_marker": null,
		"aim_has_target": false,
		"aim_target_uid": -1,
		"aim_orbit_angle": 0.0,
		"aim_orbit_dir": 1.0,
		"aim_orbit_radius_x": 0.0,
		"aim_orbit_radius_y": 0.0,
		"temp_buffs": {
			"speed_boost_percent": 0.0,
			"damage_boost_percent": 0.0,
			"hp_cost_percent": 0.0,
			"dodge_radius_percent": 0.0,
			"stack_count": 0
		},
		"encouragement_debug_count": 0,
		"hurtbox_area": null,
		"hurtbox_shape": null,
		"hurtbox_shapes": [],
		"progress_bar": null,
		"hp_bar": null,
		"shield_bg": null,
		"shield_fill": null,
		"label": null,
		"status": "down" if current_hp_value <= 0 else "alive"
	}
	_next_battle_unit_uid += 1
	var bar_template := _worker_bar_template if side == "worker" else _enemy_bar_template
	var hp_template := _worker_hp_bar_template if side == "worker" else _enemy_hp_bar_template
	var label_template := _worker_hp_label_template if side == "worker" else _enemy_hp_label_template
	var ui_rect := _get_hp_ui_rect(side, index)
	var ui_rect_progress := ui_rect
	var ui_rect_hp := ui_rect
	if hp_overhead_mode and marker != null:
		var overhead := _get_overhead_ui_rects(unit, bar_template)
		ui_rect_progress = overhead.get("progress_rect", ui_rect)
		ui_rect_hp = overhead.get("hp_rect", ui_rect)
	if bar_template:
		var bar := _duplicate_bar(bar_template, "%sBar%d" % [side, index], ui_rect_progress)
		bar.value = 0.0
		unit["progress_bar"] = bar
	if hp_template:
		var hp_bar := _duplicate_bar(hp_template, "%sHpBar%d" % [side, index], ui_rect_hp)
		hp_bar.value = 1.0
		unit["hp_bar"] = hp_bar
		var shield_rects: Dictionary = _create_shield_colorrects(hp_bar, side, index)
		unit["shield_bg"] = shield_rects.get("bg") as ColorRect
		unit["shield_fill"] = shield_rects.get("fill") as ColorRect
	if show_hp_labels and label_template:
		var label := _duplicate_label(label_template, "%sHpLabel%d" % [side, index], ui_rect)
		unit["label"] = label

	if current_hp_value <= 0:
		var progress_bar: ProgressBar = unit.get("progress_bar")
		if progress_bar:
			progress_bar.value = 0.0
			progress_bar.modulate.a = 0.0
		var hp_bar: ProgressBar = unit.get("hp_bar") as ProgressBar
		if hp_bar:
			hp_bar.value = 0.0
			hp_bar.modulate.a = 0.0
		var s_bg: ColorRect = unit.get("shield_bg") as ColorRect
		if s_bg:
			s_bg.visible = false
		var s_fill: ColorRect = unit.get("shield_fill") as ColorRect
		if s_fill:
			s_fill.visible = false
		var hp_label: Label = unit.get("label")
		if hp_label:
			hp_label.modulate.a = 0.0

	return unit


func _disable_unit_hurtbox(unit: Dictionary) -> void:
	for hurtbox_shape in _get_unit_hurtbox_shapes(unit):
		if hurtbox_shape != null:
			hurtbox_shape.disabled = true
	var hurtbox_area: Area2D = unit.get("hurtbox_area", null) as Area2D
	if hurtbox_area != null:
		hurtbox_area.monitoring = false
		hurtbox_area.monitorable = false


func _get_unit_hurtbox_shapes(unit: Dictionary) -> Array[CollisionShape2D]:
	var result: Array[CollisionShape2D] = []
	var hurtbox_shapes_v: Variant = unit.get("hurtbox_shapes", [])
	if hurtbox_shapes_v is Array:
		for shape_v in hurtbox_shapes_v:
			var shape_node: CollisionShape2D = shape_v as CollisionShape2D
			if shape_node != null and is_instance_valid(shape_node):
				result.append(shape_node)
	if not result.is_empty():
		return result
	var single_shape: CollisionShape2D = unit.get("hurtbox_shape", null) as CollisionShape2D
	if single_shape != null and is_instance_valid(single_shape):
		result.append(single_shape)
	return result


func _shape_to_target_space_rect(shape_node: CollisionShape2D) -> Rect2:
	if shape_node == null or shape_node.disabled or shape_node.shape == null:
		return Rect2()
	var points: PackedVector2Array = _get_shape_local_points(shape_node.shape)
	if points.is_empty():
		return Rect2()
	var first_point: Vector2 = shape_node.global_transform * points[0]
	if _attack_fx_root != null and is_instance_valid(_attack_fx_root):
		first_point = _attack_fx_root.to_local(first_point)
	var min_point: Vector2 = first_point
	var max_point: Vector2 = first_point
	for i in range(1, points.size()):
		var transformed: Vector2 = shape_node.global_transform * points[i]
		if _attack_fx_root != null and is_instance_valid(_attack_fx_root):
			transformed = _attack_fx_root.to_local(transformed)
		min_point.x = minf(min_point.x, transformed.x)
		min_point.y = minf(min_point.y, transformed.y)
		max_point.x = maxf(max_point.x, transformed.x)
		max_point.y = maxf(max_point.y, transformed.y)
	return Rect2(min_point, max_point - min_point)


func _get_shape_local_points(shape: Shape2D) -> PackedVector2Array:
	if shape == null:
		return PackedVector2Array()
	if shape is RectangleShape2D:
		var rect_shape: RectangleShape2D = shape as RectangleShape2D
		var half_size: Vector2 = rect_shape.size * 0.5
		return PackedVector2Array([
			Vector2(-half_size.x, -half_size.y),
			Vector2(half_size.x, -half_size.y),
			Vector2(half_size.x, half_size.y),
			Vector2(-half_size.x, half_size.y),
		])
	if shape is ConvexPolygonShape2D:
		return (shape as ConvexPolygonShape2D).points
	if shape is ConcavePolygonShape2D:
		return (shape as ConcavePolygonShape2D).segments
	if shape is CircleShape2D:
		var circle_shape: CircleShape2D = shape as CircleShape2D
		var radius: float = circle_shape.radius
		return PackedVector2Array([
			Vector2(-radius, -radius),
			Vector2(radius, -radius),
			Vector2(radius, radius),
			Vector2(-radius, radius),
		])
	if shape is CapsuleShape2D:
		var capsule_shape: CapsuleShape2D = shape as CapsuleShape2D
		var half_height: float = maxf(capsule_shape.height * 0.5, capsule_shape.radius)
		var radius: float = capsule_shape.radius
		return PackedVector2Array([
			Vector2(-radius, -half_height),
			Vector2(radius, -half_height),
			Vector2(radius, half_height),
			Vector2(-radius, half_height),
		])
	return PackedVector2Array()


func _get_actor_battle_frame_size(actor: BattleActor) -> Vector2:
	if actor == null or actor.portrait_texture == null:
		return Vector2(32.0, 32.0)
	if actor.battle_use_sheet:
		return Vector2(
			maxf(actor.portrait_texture.get_width() / float(max(actor.battle_sheet_hframes, 1)), 1.0),
			maxf(actor.portrait_texture.get_height() / float(max(actor.battle_sheet_vframes, 1)), 1.0)
		)
	return actor.portrait_texture.get_size()


func _get_hp_ui_rect(side: String, index: int) -> Rect2:
	var template := _worker_bar_template if side == "worker" else _enemy_bar_template
	if template == null:
		return Rect2(0.0, 0.0, 120.0, 0.0)

	if not hp_ui_horizontal:
		return Rect2(template.offset_left, party_row_spacing * float(index), template.offset_right - template.offset_left, 0.0)

	var viewport_w: float = battle_box_size.x if battle_box_size.x > 0.0 else 640.0
	var mid_x: float = viewport_w * 0.5
	var side_min: float = hp_ui_edge_margin
	var side_max: float = mid_x - hp_ui_center_gap
	var count: int = max(_desired_worker_count, 1)
	if side == "enemy":
		side_min = mid_x + hp_ui_center_gap
		side_max = viewport_w - hp_ui_edge_margin
		count = max(_desired_enemy_count, 1)

	var template_width: float = template.offset_right - template.offset_left
	var available_w: float = maxf(side_max - side_min, 1.0)
	var gap: float = maxf(hp_ui_min_spacing, 0.0)
	if count > 1:
		var min_slot_for_gap := (available_w - gap * float(count - 1)) / float(count)
		if min_slot_for_gap < hp_ui_min_slot_width:
			gap = maxf((available_w - hp_ui_min_slot_width * float(count)) / float(count - 1), 2.0)

	var slot_w := (available_w - gap * float(max(count - 1, 0))) / float(max(count, 1))
	slot_w = clampf(slot_w, 36.0, template_width)

	var left := side_min + float(index) * (slot_w + gap)
	left = clampf(left, side_min, side_max - slot_w)
	return Rect2(left, 0.0, slot_w, 0.0)


func _create_shield_colorrects(hp_bar: ProgressBar, side: String, index: int) -> Dictionary:
	# 护盾条用两个 ColorRect 实现：bg（全宽背景）+ fill（按比例填充）
	# 直接作为 hp_bar 的兄弟节点添加到同一父节点，z_index 高于 hp_bar
	var parent := hp_bar.get_parent()
	if parent == null:
		return {}
	var h: float = maxf((hp_bar.offset_bottom - hp_bar.offset_top) * clampf(shield_bar_height_ratio, 0.1, 1.0), 1.0)
	var x: float = hp_bar.offset_left
	var y: float = hp_bar.offset_top
	var w: float = hp_bar.offset_right - hp_bar.offset_left

	var bg := ColorRect.new()
	bg.name = "%sShieldBg%d" % [side, index]
	bg.color = Color(0.0, 0.0, 0.0, 0.0)
	bg.mouse_filter = Control.MOUSE_FILTER_IGNORE
	_promote_battle_ui_canvas_item(bg, BATTLE_UI_SHIELD_BG_Z)
	bg.layout_mode = 0
	bg.offset_left = x
	bg.offset_top = y
	bg.offset_right = x + w
	bg.offset_bottom = y + h
	bg.visible = false
	bg.add_to_group("battle_ui_dynamic")
	parent.add_child(bg)

	var fill := ColorRect.new()
	fill.name = "%sShieldFill%d" % [side, index]
	fill.color = shield_bar_color
	fill.mouse_filter = Control.MOUSE_FILTER_IGNORE
	_promote_battle_ui_canvas_item(fill, BATTLE_UI_SHIELD_FILL_Z)
	fill.layout_mode = 0
	fill.offset_left = x
	fill.offset_top = y
	fill.offset_right = x  # 初始宽度为0
	fill.offset_bottom = y + h
	fill.visible = false
	fill.add_to_group("battle_ui_dynamic")
	parent.add_child(fill)

	return {"bg": bg, "fill": fill}

func _duplicate_bar(template: ProgressBar, name: String, ui_rect: Rect2) -> ProgressBar:
	var bar := template.duplicate()
	bar.name = name
	bar.visible = true
	bar.layout_mode = template.layout_mode
	bar.anchor_left = template.anchor_left
	bar.anchor_top = template.anchor_top
	bar.anchor_right = template.anchor_right
	bar.anchor_bottom = template.anchor_bottom
	var template_h := template.offset_bottom - template.offset_top
	var h := ui_rect.size.y if ui_rect.size.y > 0.0 else template_h
	bar.offset_left = ui_rect.position.x
	bar.offset_top = ui_rect.position.y
	bar.offset_right = ui_rect.position.x + ui_rect.size.x
	bar.offset_bottom = ui_rect.position.y + h
	bar.custom_minimum_size = template.custom_minimum_size
	bar.size_flags_horizontal = template.size_flags_horizontal
	bar.size_flags_vertical = template.size_flags_vertical
	bar.pivot_offset = template.pivot_offset
	bar.min_value = 0.0
	bar.max_value = 1.0
	bar.show_percentage = false
	_promote_battle_ui_canvas_item(bar, BATTLE_UI_BAR_Z)
	bar.add_to_group("battle_ui_dynamic")
	var parent := template.get_parent()
	if parent:
		parent.add_child(bar)
	else:
		add_child(bar)
	return bar


func _get_overhead_ui_rects(unit: Dictionary, template: ProgressBar) -> Dictionary:
	var marker := unit.get("marker") as Marker2D
	if marker == null:
		return {}

	var ui_parent := template.get_parent() as CanvasItem
	if ui_parent == null:
		return {}

	var head_pos := _get_unit_head_ui_position(marker, ui_parent)
	var actor := unit.get("actor") as BattleActor
	var max_hp: int = maxi(int(unit.get("max_hp", 0)), 1)
	if max_hp <= 1 and actor != null:
		max_hp = maxi(actor.max_hp, 1)

	# 宽度随 max_hp 对数缩放，边际收敛，以 hp_overhead_max_hp_reference 为基准
	# scale = log2(max_hp / ref + 1) / log2(2) = log2(ratio + 1)
	# ratio=1 时 scale=1（基准宽度），ratio 越大增长越慢
	var ref_hp: float = maxf(hp_overhead_max_hp_reference, 1.0)
	var ratio: float = float(max_hp) / ref_hp
	var hp_scale: float = log(ratio + 1.0) / log(2.0)  # log2(ratio+1)，ratio=1时=1
	var width: float = clampf(hp_overhead_width * hp_scale, hp_overhead_width_min, hp_overhead_width_max)

	var side: String = String(unit.get("side", "worker"))
	var index: int = int(unit.get("index", 0))
	var slot_offset: Vector2 = _get_overhead_slot_offset(side, index)
	var actor_offset: Vector2 = actor.overhead_hp_offset if actor != null else Vector2.ZERO

	var x: float = head_pos.x - width * 0.5 + slot_offset.x + actor_offset.x
	var base_y: float = head_pos.y + hp_overhead_y_offset + slot_offset.y + actor_offset.y
	var progress_h: float = maxf(hp_overhead_progress_height, 1.0)
	var hp_h: float = maxf(hp_overhead_hp_height, 1.0)
	var gap: float = maxf(hp_overhead_bar_gap, 0.0)

	var progress_rect := Rect2(x, base_y, width, progress_h)
	var hp_rect := Rect2(x, base_y + progress_h + gap, width, hp_h)
	return {
		"progress_rect": progress_rect,
		"hp_rect": hp_rect,
		"bar_width": width,
	}


func _get_unit_head_ui_position(marker: Marker2D, ui_parent: CanvasItem) -> Vector2:
	# In this scene the markers (Node2D) and HP bars (Control) live under the same
	# battle root. Using global_position delta is the most stable in editor preview.
	var marker_global: Vector2 = marker.global_position
	var parent_global: Vector2 = ui_parent.global_position
	return marker_global - parent_global


func _update_overhead_ui_positions() -> void:
	_update_overhead_for_units(_worker_units)
	_update_overhead_for_units(_enemy_units)


func _update_overhead_for_units(units: Array) -> void:
	for unit in units:
		var marker := unit.get("marker") as Marker2D
		var bar := unit.get("progress_bar") as ProgressBar
		var hp_bar: ProgressBar = unit.get("hp_bar") as ProgressBar
		if marker == null or bar == null or hp_bar == null:
			continue

		var overhead := _get_overhead_ui_rects(unit, bar)
		var progress_rect: Rect2 = overhead.get("progress_rect", Rect2())
		var hp_rect: Rect2 = overhead.get("hp_rect", Rect2())

		_set_control_rect(bar, progress_rect)
		_set_control_rect(hp_bar, hp_rect)

		# 护盾条跟随血条位置，高度按比例缩小
		# 宽度相对血条宽度，按护盾/max_hp比例缩放
		var shield_bg: ColorRect = unit.get("shield_bg") as ColorRect
		var shield_fill: ColorRect = unit.get("shield_fill") as ColorRect
		if shield_bg != null and shield_fill != null:
			var sh: float = maxf(hp_rect.size.y * clampf(shield_bar_height_ratio, 0.1, 1.0), 1.0)
			var shield_val: int = maxi(int(unit.get("shield", 0)), 0)
			var max_hp_val: int = maxi(int(unit.get("max_hp", 1)), 1)
			# 护盾条宽度 = 血条宽度 × (shield / maxHP)，可超过血条，但不超过 max_width
			var hp_bar_width: float = hp_rect.size.x
			var shield_ratio: float = float(shield_val) / float(max_hp_val)
			var shield_w: float = clampf(hp_bar_width * shield_ratio, 0.0, hp_overhead_width_max)
			shield_bg.offset_left = hp_rect.position.x
			shield_bg.offset_top = hp_rect.position.y
			shield_bg.offset_right = hp_rect.position.x + shield_w
			shield_bg.offset_bottom = hp_rect.position.y + sh
			shield_fill.offset_left = hp_rect.position.x
			shield_fill.offset_top = hp_rect.position.y
			shield_fill.offset_right = hp_rect.position.x + shield_w
			shield_fill.offset_bottom = hp_rect.position.y + sh

		var label := unit.get("label") as Label
		if label != null:
			_set_control_rect(label, Rect2(progress_rect.position.x, progress_rect.position.y - 14.0, progress_rect.size.x, 12.0))


func _get_overhead_slot_offset(side: String, index: int) -> Vector2:
	var arr: PackedVector2Array = worker_overhead_slot_offsets if side == "worker" else enemy_overhead_slot_offsets
	if index >= 0 and index < arr.size():
		return arr[index]
	return Vector2.ZERO


func _set_control_rect(control: Control, rect: Rect2) -> void:
	if control == null:
		return
	control.offset_left = rect.position.x
	control.offset_top = rect.position.y
	control.offset_right = rect.position.x + rect.size.x
	control.offset_bottom = rect.position.y + rect.size.y


func _promote_battle_ui_canvas_item(item: CanvasItem, absolute_z_index: int) -> void:
	if item == null:
		return
	item.z_as_relative = false
	item.z_index = absolute_z_index


func _make_preview_actor(name: String) -> BattleActor:
	var actor := BattleActor.new()
	actor.display_name = name
	actor.max_hp = 20
	actor.max_mp = 15
	actor.damage = 1
	actor.attack_time = 1.0
	actor.attack_speed_multiplier = 1.0
	return actor


func _update_editor_anchor_gizmos() -> void:
	_clear_editor_anchor_gizmos()
	for unit in _worker_units:
		_add_editor_anchor_gizmo(unit, preview_worker_anchor_color)
	for unit in _enemy_units:
		_add_editor_anchor_gizmo(unit, preview_enemy_anchor_color)


func _add_editor_anchor_gizmo(unit: Dictionary, color: Color) -> void:
	var marker := unit.get("marker") as Marker2D
	var bar := unit.get("progress_bar") as ProgressBar
	if marker == null or bar == null:
		return
	var ui_parent := bar.get_parent() as CanvasItem
	if ui_parent == null:
		return

	var head_pos: Vector2 = _get_unit_head_ui_position(marker, ui_parent)
	var half: float = maxf(preview_anchor_size * 0.5, 1.0)

	var h := ColorRect.new()
	h.color = color
	h.mouse_filter = Control.MOUSE_FILTER_IGNORE
	_promote_battle_ui_canvas_item(h, BATTLE_UI_PREVIEW_GIZMO_Z)
	h.offset_left = head_pos.x - half
	h.offset_top = head_pos.y - 1.0
	h.offset_right = head_pos.x + half
	h.offset_bottom = head_pos.y + 1.0
	h.add_to_group("battle_ui_preview_anchor")
	ui_parent.add_child(h)

	var v := ColorRect.new()
	v.color = color
	v.mouse_filter = Control.MOUSE_FILTER_IGNORE
	_promote_battle_ui_canvas_item(v, BATTLE_UI_PREVIEW_GIZMO_Z)
	v.offset_left = head_pos.x - 1.0
	v.offset_top = head_pos.y - half
	v.offset_right = head_pos.x + 1.0
	v.offset_bottom = head_pos.y + half
	v.add_to_group("battle_ui_preview_anchor")
	ui_parent.add_child(v)


func _clear_editor_anchor_gizmos() -> void:
	for node in get_tree().get_nodes_in_group("battle_ui_preview_anchor"):
		if node is Node:
			node.queue_free()

func _duplicate_label(template: Label, name: String, ui_rect: Rect2) -> Label:
	var label := template.duplicate()
	label.name = name
	label.visible = true
	label.layout_mode = template.layout_mode
	label.anchor_left = template.anchor_left
	label.anchor_top = template.anchor_top
	label.anchor_right = template.anchor_right
	label.anchor_bottom = template.anchor_bottom
	var h := template.offset_bottom - template.offset_top
	label.offset_left = ui_rect.position.x
	label.offset_top = template.offset_top + ui_rect.position.y
	label.offset_right = ui_rect.position.x + ui_rect.size.x
	label.offset_bottom = template.offset_top + ui_rect.position.y + h
	label.horizontal_alignment = HORIZONTAL_ALIGNMENT_CENTER
	label.clip_text = true
	label.custom_minimum_size = template.custom_minimum_size
	label.size_flags_horizontal = template.size_flags_horizontal
	label.size_flags_vertical = template.size_flags_vertical
	label.pivot_offset = template.pivot_offset
	_promote_battle_ui_canvas_item(label, BATTLE_UI_LABEL_Z)
	label.add_to_group("battle_ui_dynamic")
	var parent := template.get_parent()
	if parent:
		parent.add_child(label)
	else:
		add_child(label)
	return label

func _build_worker_world_nodes() -> Array[Node]:
	var nodes: Array[Node] = []
	var leader_node := get_node_or_null(leader_world_path)
	if leader_node:
		nodes.append(leader_node)
	var extras_count: int = max(_worker_units.size() - (1 if leader_actor else 0), 0)
	for i in range(min(worker_world_paths.size(), extras_count)):
		var path := worker_world_paths[i]
		var node := get_node_or_null(path)
		if node:
			nodes.append(node)
	return nodes

func _build_enemy_world_nodes() -> Array[Node]:
	var nodes: Array[Node] = []
	if _battle_enemy_node:
		nodes.append(_battle_enemy_node)
	var extras_count: int = max(_enemy_units.size() - (1 if _battle_enemy_node else 0), 0)
	for i in range(min(enemy_world_paths.size(), extras_count)):
		var path := enemy_world_paths[i]
		var node := get_node_or_null(path)
		if node:
			nodes.append(node)
	return nodes
