        "-var _attack_fx_root: Node2D = null",
        "-var _battle_engine: BattleEngine = null",
        "-var _next_battle_unit_uid: int = 1",
        "-",
        "-",
        "-func _ready():",
        "-	process_mode = Node.PROCESS_MODE_ALWAYS",
        "-	self.hide()",
        "-	_customize_battle_box()",
        "-	_resolve_enemy_templates()",
        "-	_hide_ui_templates()",
        "-	_ensure_attack_aim_root()",
        "-	_ensure_attack_fx_root()",
        "-	if Engine.is_editor_hint():",
        "-		self.show()",
        "-		set_process(true)",
        "-		return",
        "-	# 监听全局战斗信号",
        "-	GameEvents.battle_started.connect(_on_battle_started)",
        "-",
        "-func _resolve_enemy_templates() -> void:",
        "-	if _enemy_bar_template == null:",
        "-		_enemy_bar_template = get_node_or_null("BossBar") as ProgressBar",
        "-	if _enemy_hp_bar_template == null:",
        "-		_enemy_hp_bar_template = get_node_or_null("BossHpBar") as ProgressBar",
        "-	if _enemy_ghost_template == null:",
        "-		_enemy_ghost_template = get_node_or_null("BossHpTrailBar") as ProgressBar",
        "-	if _enemy_hp_label_template == null:",
        "-		_enemy_hp_label_template = get_node_or_null("BossHpLabel") as Label",
        "-",
        "-",
        "-func _ensure_attack_fx_root() -> void:",
        "-	if _attack_fx_root != null and is_instance_valid(_attack_fx_root):",
        "-		_attack_fx_root.z_index = BATTLE_ATTACK_FX_Z",
        "-		_attack_fx_root.z_as_relative = false",
        "-		return",
        "-	_attack_fx_root = get_node_or_null("AttackFxRoot") as Node2D",
        "-	if _attack_fx_root != null:",
        "-		_attack_fx_root.z_index = BATTLE_ATTACK_FX_Z",
        "-		_attack_fx_root.z_as_relative = false",
        "-		return",
        "-	_attack_fx_root = Node2D.new()",
        "-	_attack_fx_root.name = "AttackFxRoot"",
        "-	_attack_fx_root.z_index = BATTLE_ATTACK_FX_Z",
        "-	_attack_fx_root.z_as_relative = false",
        "-	add_child(_attack_fx_root)",
        "-",
        "-",
        "-func _ensure_attack_aim_root() -> void:",
        "-	if _attack_aim_root != null and is_instance_valid(_attack_aim_root):",
        "-		_attack_aim_root.z_index = BATTLE_AIM_MARKER_Z",
        "-		_attack_aim_root.z_as_relative = false",
        "-		return",
        "-	_attack_aim_root = get_node_or_null("AttackAimRoot") as Node2D",
        "-	if _attack_aim_root != null:",
        "-		_attack_aim_root.z_index = BATTLE_AIM_MARKER_Z",
        "-		_attack_aim_root.z_as_relative = false",
        "-		return",
        "-	_attack_aim_root = Node2D.new()",
        "-	_attack_aim_root.name = "AttackAimRoot"",
        "-	_attack_aim_root.z_index = BATTLE_AIM_MARKER_Z",
        "-	_attack_aim_root.z_as_relative = false",
        "-	add_child(_attack_aim_root)",
        "-",
        "-func _process(delta: float) -> void:",
        "-	if Engine.is_editor_hint():",
        "-		_editor_preview_process()",
        "-		return",
        "-	if not _battle_active:",
        "-		return",
        "-	_update_battle_loop(delta)",
        "-",
        "-",
        "-func _editor_preview_process() -> void:",
        "-	_force_hide_ui_templates()",
        "-",
        "-	if not preview_overhead_in_editor:",
        "-		if _editor_preview_initialized:",
        "-			_clear_dynamic_ui()",
        "-			_editor_preview_initialized = false",
        "-			_editor_preview_signature = """,
        "-		return",
        "-",
        "-	var sig: String = "%d|%d|%s|%s|%s|%s|%s|%s|%s|%s|%s" % [",
        "-		preview_worker_count,",
        "-		preview_enemy_count,",
        "-		str(hp_overhead_mode),",
        "-		str(hp_overhead_width),",
        "-		str(hp_overhead_y_offset),",
        "-		str(hp_overhead_hp_height),",
        "-		str(hp_overhead_progress_height),",
        "-		str(worker_overhead_slot_offsets),",
        "-		str(enemy_overhead_slot_offsets),",
        "-		str(preview_show_anchor_gizmos),",
        "-		str(preview_anchor_size)",
        "-	]",
        "-",
        "-	if not _editor_preview_initialized or sig != _editor_preview_signature:",
        "-		_clear_dynamic_ui()",
        "-		_desired_worker_count = clampi(preview_worker_count, 1, 4)",
        "-		_desired_enemy_count = clampi(preview_enemy_count, 1, 4)",
        "-		_worker_units = _build_worker_units()",
        "-		_enemy_units = _build_enemy_units()",
        "-		_apply_layouts()",
        "-		_update_all_unit_ui()",
        "-		_editor_preview_initialized = true",
        "-		_editor_preview_signature = sig",
        "-",
        "-	if hp_overhead_mode:",
        "-		_update_overhead_ui_positions()",
        "-",
        "-	if preview_show_anchor_gizmos:",
        "-		_update_editor_anchor_gizmos()",
        "-	else:",
        "-		_clear_editor_anchor_gizmos()",
        "-",
        "-",
        "-func _exit_tree() -> void:",
        "-	if Engine.is_editor_hint():",
        "-		_clear_dynamic_ui()",
        "-",
        "-",
        "-func _unhandled_input(event: InputEvent) -> void:",
        "-	if not _battle_active:",
        "-		return",
        "-	if not (event is InputEventKey):",
        "-		return",
        "-	var key_event: InputEventKey = event as InputEventKey",
        "-	if not key_event.pressed or key_event.echo:",
        "-		return",
        "-",
        "-	if key_event.physical_keycode == KEY_1:",
        "-		_try_cast_teammate_ultimate(0)",
        "-		_mark_input_handled()",
        "-	elif key_event.physical_keycode == KEY_2:",
        "-		_try_cast_teammate_ultimate(1)",
        "-		_mark_input_handled()",
        "-	elif key_event.physical_keycode == KEY_3:",
        "-		_try_cast_teammate_ultimate(2)",
        "-		_mark_input_handled()",
        "-",
        "-",
        "-func _mark_input_handled() -> void:",
        "-	if not is_inside_tree():",
        "-		return",
        "-	var vp := get_viewport()",
        "-	if vp != null:",
        "-		vp.set_input_as_handled()",
        "-",
        "-",
        "-func _try_cast_teammate_ultimate(teammate_index: int) -> Dictionary:",
        "-	return _try_encourage_teammate(teammate_index)",
        "-",
        "-",
        "-func _try_encourage_actor(actor: BattleActor) -> Dictionary:",
        "-	return _apply_encouragement_to_actor(actor)",
        "-",
        "-",
        "-func _try_encourage_teammate(teammate_index: int) -> Dictionary:",
        "-	var party: Array = []",
        "-	if GameEvents.has_method("get_worker_party"):",
        "-		party = GameEvents.get_worker_party()",
        "-	else:",
        "-		var wp: Variant = GameEvents.get("worker_party")",
        "-		if wp is Array:",
        "-			party = wp",
        "-",
        "-	if teammate_index < 0 or teammate_index >= party.size():",
        "-		return {"ok": false, "message": "当前没有可鼓励的队友。"}",
        "-",
        "-	var actor: BattleActor = party[teammate_index] as BattleActor",
        "-	return _apply_encouragement_to_actor(actor)",
        "-",
        "-",
        "-func _apply_encouragement_to_actor(actor: BattleActor) -> Dictionary:",
        "-	if _battle_engine == null:",
        "-		return {"ok": false, "message": "战斗系统未初始化。"}",
        "-	var gold_available: float = GameEvents.get_gold() if GameEvents != null and GameEvents.has_method("get_gold") else 0.0",
        "-	var result: Dictionary = _battle_engine.apply_encouragement(actor, gold_available)",
        "-	if result.get("ok", false):",
        "-		var cost: float = result.get("cost", 0.0)",
        "-		if GameEvents != null and GameEvents.has_method("spend_gold"):",
        "-			GameEvents.spend_gold(cost)",
        "-		var unit_uid: int = result.get("uid", -1)",
        "-		if unit_uid >= 0:",
        "-			_sync_unit_from_engine(unit_uid)",
        "-	return result",
        "-",
        "-func _customize_battle_box() -> void:",
        "-	if _battle_frame:",
        "-		battle_box_size = _battle_frame.size",
        "-",
        "-func _on_battle_started(_enemy_node):",
        "-	if _battle_active:",
        "-		return",
        "-	_battle_active = true",
        "-	if GameEvents != null and GameEvents.has_method("set_battle_active"):",
        "-		GameEvents.set_battle_active(true)",
        "-	_battle_enemy_node = _enemy_node",
        "-	_setup_battle_stats()",
        "-	_ensure_battle_layer_visible()",
        "-	self.show()",
        "-	_spawn_battle_sprites()",
        "-	_switch_to_battle_camera()",
        "-	GameEvents.pause_world()",
        "-	print("画中画：战斗开始，世界已静止...")",
        "-	",
        "-",
        "-func _finish_battle():",
        "-	self.hide()",
        "-	_clear_attack_fx_instances()",
        "-	_clear_battle_sprites()",
        "-	_restore_previous_camera()",
        "-	_battle_active = false",
        "-	if _battle_engine != null:",
        "-		_battle_engine.clear_all_temp_buffs()",
        "-	_hide_battle_layer()",
        "-	if GameEvents != null and GameEvents.has_method("set_battle_active"):",
        "-		GameEvents.set_battle_active(false)",
        "-	GameEvents.resume_world()",
        "-	GameEvents.battle_finished.emit()",
        "-	_remove_defeated_nodes()",
        "-",
        "-",
        "-func _spawn_battle_sprites() -> void:",
        "-	_clear_battle_sprites()",
        "-	for unit in _worker_units:",
        "-		_create_unit_view(unit, "worker")",
        "-	for unit in _enemy_units:",
        "-		_create_unit_view(unit, "enemy")",
        "-	_refresh_battle_unit_draw_order()",
        "-	_spawn_attack_aim_markers()",
        "-",
        "-func _clear_battle_sprites() -> void:",
        "-	_clear_attack_aim_markers()",
        "-	_clear_attack_fx_instances()",
        "-	for unit in _worker_units:",
        "-		var view: Node2D = unit.get("view") as Node2D",
        "-		if view != null and is_instance_valid(view):",
        "-			view.queue_free()",
        "-		unit["view"] = null",
        "-		unit["sprite"] = null",
        "-		unit["hurtbox_area"] = null",
        "-		unit["hurtbox_shape"] = null",
        "-		unit["hurtbox_shapes"] = []",
        "-		unit["aim_marker"] = null",
        "-		unit["aim_has_target"] = false",
        "-		unit["aim_target_uid"] = -1",
        "-		unit["aim_orbit_angle"] = 0.0",
        "-		unit["aim_orbit_dir"] = 1.0",
        "-		unit["aim_orbit_radius_x"] = 0.0",
        "-		unit["aim_orbit_radius_y"] = 0.0",
        "-	for unit in _enemy_units:",
        "-		var view: Node2D = unit.get("view") as Node2D",
        "-		if view != null and is_instance_valid(view):",
        "-			view.queue_free()",
        "-		unit["view"] = null",
        "-		unit["sprite"] = null",
        "-		unit["hurtbox_area"] = null",
        "-		unit["hurtbox_shape"] = null",
        "-		unit["hurtbox_shapes"] = []",
        "-		unit["aim_marker"] = null",
        "-		unit["aim_has_target"] = false",
        "-		unit["aim_target_uid"] = -1",
        "-		unit["aim_orbit_angle"] = 0.0",
        "-		unit["aim_orbit_dir"] = 1.0",
        "-		unit["aim_orbit_radius_x"] = 0.0",
        "-		unit["aim_orbit_radius_y"] = 0.0",
        "-",
        "-",
        "-func _clear_attack_fx_instances() -> void:",
        "-	if _attack_fx_root == null or not is_instance_valid(_attack_fx_root):",
        "-		return",
        "-	for child in _attack_fx_root.get_children():",
        "-		if child is Node:",
        "-			(child as Node).queue_free()",
        "-",
        "-",
        "-func _clear_attack_aim_markers() -> void:",
        "-	if _attack_aim_root == null or not is_instance_valid(_attack_aim_root):",
        "-		return",
        "-	for child in _attack_aim_root.get_children():",
        "-		if child is Node:",
        "-			(child as Node).queue_free()",
        "-",
        "-func _create_unit_view(unit: Dictionary, side: String) -> void:",
        "-	var marker: Marker2D = unit.get("marker") as Marker2D",
        "-	var actor: BattleActor = unit.get("actor") as BattleActor",
        "-	if marker == null or actor == null:",
        "-		return",
        "-	var view_scene: PackedScene = _resolve_unit_view_scene(actor)",
        "-	if view_scene == null:",
        "-		return",
        "-	var view_node: Node = view_scene.instantiate()",
        "-	var view: BattleUnitView = view_node as BattleUnitView",
        "-	if view == null:",
        "-		if view_node != null:",
        "-			view_node.queue_free()",
        "-		return",
        "-	marker.add_child(view)",
        "-	view.setup(actor, side, battle_sprite_scale)",
        "-	unit["view"] = view",
        "-	unit["hurtbox_area"] = view.get_hurtbox_area()",
        "-	unit["hurtbox_shape"] = view.get_hurtbox_shape()",
        "-	unit["hurtbox_shapes"] = view.get_hurtbox_shapes()",
        "-	var display_node: CanvasItem = view.get_display_node()",
        "-	unit["sprite"] = display_node",
        "-	if display_node != null and unit.get("status", "alive") != "alive":",
        "-		display_node.modulate.a = 0.0",
        "-	_refresh_battle_unit_draw_order()",
        "-",
        "-",
        "-func _refresh_battle_unit_draw_order() -> void:",
        "-	var sortable_units: Array[Dictionary] = []",
        "-	for unit_v in _worker_units:",
        "-		if unit_v is Dictionary:",
        "-			sortable_units.append(unit_v as Dictionary)",
        "-	for unit_v in _enemy_units:",
        "-		if unit_v is Dictionary:",
        "-			sortable_units.append(unit_v as Dictionary)",
        "-",
        "-	sortable_units.sort_custom(func(a: Dictionary, b: Dictionary) -> bool:",
        "-		var marker_a: Marker2D = a.get("marker") as Marker2D",
        "-		var marker_b: Marker2D = b.get("marker") as Marker2D",
        "-		var y_a: float = marker_a.global_position.y if marker_a != null and is_instance_valid(marker_a) else -INF",
        "-		var y_b: float = marker_b.global_position.y if marker_b != null and is_instance_valid(marker_b) else -INF",
        "-		if not is_equal_approx(y_a, y_b):",
        "-			return y_a < y_b",
        "-		return int(a.get("uid", 0)) < int(b.get("uid", 0))",
        "-	)",
        "-",
        "-	for i in range(sortable_units.size()):",
        "-		var unit: Dictionary = sortable_units[i]",
        "-		var view: CanvasItem = unit.get("view") as CanvasItem",
        "-		if view == null or not is_instance_valid(view):",
        "-			continue",
        "-		view.z_as_relative = false",
        "-		view.z_index = BATTLE_UNIT_SORT_Z_BASE + i",
        "-",
        "-",
        "-func _resolve_unit_view_scene(actor: BattleActor) -> PackedScene:",
        "-	if actor != null and actor.battle_view_scene != null:",
        "-		return actor.battle_view_scene",
        "-	if default_battle_unit_view_scene != null:",
        "-		return default_battle_unit_view_scene",
        "-	return BATTLE_UNIT_VIEW_SCENE",
        "-",
        "-",
        "-func _spawn_attack_aim_markers() -> void:",
        "-	_ensure_attack_aim_root()",
        "-	if _attack_aim_root == null or not is_instance_valid(_attack_aim_root):",
        "-		return",
        "-	for unit in _worker_units:",
        "-		_create_attack_aim_marker(unit)",
        "-	for unit in _enemy_units:",
        "-		_create_attack_aim_marker(unit)",
        "-",
        "-",
        "-func _create_attack_aim_marker(unit: Dictionary) -> void:",
        "-	if _attack_aim_root == null or not is_instance_valid(_attack_aim_root):",
        "-		return",
        "-	var actor: BattleActor = unit.get("actor") as BattleActor",
        "-	if actor == null:",
        "-		return",
        "-	var marker_scene: PackedScene = attack_aim_marker_scene if attack_aim_marker_scene != null else BATTLE_AIM_MARKER_SCENE",
        "-	var marker_node: Node2D = null",
        "-	if marker_scene != null:",
        "-		marker_node = marker_scene.instantiate() as Node2D",
        "-	if marker_node == null:",
        "-		marker_node = Node2D.new()",
        "-		var sprite := Sprite2D.new()",
        "-		sprite.name = "Sprite2D"",
        "-		sprite.texture = ATTACK_AIM_TEXTURE",
        "-		marker_node.add_child(sprite)",
        "-	marker_node.name = "AimMarker_%s_%d" % [String(unit.get("side", "unit")), int(unit.get("uid", 0))]",
        "-	_attack_aim_root.add_child(marker_node)",
        "-	unit["aim_marker"] = marker_node",
        "-	unit["aim_has_target"] = false",
        "-	_apply_attack_aim_marker_color(unit)",
        "-	var target_side: String = "enemy" if String(unit.get("side", "worker")) == "worker" else "worker"",
        "-	var alive_targets: Array = _get_alive_units(_enemy_units if target_side == "enemy" else _worker_units)",
        "-	if not _assign_new_attack_aim_target(unit, alive_targets, true):",
        "-		_set_attack_aim_marker_visible(unit, false)",
        "-		return",
        "-	_update_attack_aim_marker_visibility(unit, true)",
        "-",
        "-",
        "-func _apply_attack_aim_marker_color(unit: Dictionary) -> void:",
        "-	var marker_node: Node2D = unit.get("aim_marker") as Node2D",
        "-	if marker_node == null:",
        "-		return",
        "-	var sprite: Sprite2D = _get_attack_aim_marker_sprite(marker_node)",
        "-	if sprite == null:",
        "-		return",
        "-	sprite.modulate = _get_attack_aim_marker_color(unit)",
        "-",
        "-",
        "-func _get_attack_aim_marker_sprite(marker_node: Node2D) -> Sprite2D:",
        "-	if marker_node == null:",
        "-		return null",
        "-	if marker_node is Sprite2D:",
        "-		return marker_node as Sprite2D",
        "-	return marker_node.get_node_or_null("Sprite2D") as Sprite2D",
        "-",
        "-",
        "-func _get_attack_aim_marker_color(unit: Dictionary) -> Color:",
        "-	var actor: BattleActor = unit.get("actor") as BattleActor",
        "-	if actor != null and actor.battle_aim_marker_color.a > 0.0:",
        "-		return actor.battle_aim_marker_color",
        "-	return _get_auto_attack_aim_marker_color(String(unit.get("side", "worker")), int(unit.get("index", 0)))",
        "-",
        "-",
        "-func _get_auto_attack_aim_marker_color(side: String, index: int) -> Color:",
        "-	var palette_worker: Array[Color] = [",
        "-		Color(0.35, 0.95, 1.0, 0.95),",
        "-		Color(0.55, 1.0, 0.65, 0.95),",
        "-		Color(1.0, 0.9, 0.35, 0.95),",
        "-		Color(0.7, 0.8, 1.0, 0.95),",
        "-	]",
        "-	var palette_enemy: Array[Color] = [",
        "-		Color(1.0, 0.45, 0.35, 0.95),",
        "-		Color(1.0, 0.72, 0.28, 0.95),",
        "-		Color(1.0, 0.35, 0.65, 0.95),",
        "-		Color(0.95, 0.55, 1.0, 0.95),",
        "-	]",
        "-	var palette: Array[Color] = palette_worker if side == "worker" else palette_enemy",
        "-	if palette.is_empty():",
        "-		return Color(1.0, 1.0, 1.0, 0.95)",
        "-	return palette[posmod(index, palette.size())]",
        "-",
        "-",
        "-func _switch_to_battle_camera() -> void:",
        "-	if _battle_cam == null:",
        "-		return",
        "-	_previous_camera = get_viewport().get_camera_2d()",
        "-	_battle_cam.make_current()",
        "-",
        "-func _restore_previous_camera() -> void:",
        "-	if _previous_camera and is_instance_valid(_previous_camera):",
        "-		_previous_camera.make_current()",
        "-	_previous_camera = null",
        "-",
        "-func _setup_battle_stats() -> void:",
        "-	_clear_dynamic_ui()",
        "-	_battle_engine = BattleEngine.new()",
        "-	_configure_battle_engine()",
        "-	_battle_engine.reset()",
        "-	_next_battle_unit_uid = 1",
        "-	_desired_worker_count = _get_desired_worker_count()",
        "-	_desired_enemy_count = _get_desired_enemy_count()",
        "-	_worker_units = _build_worker_units()",
        "-	_enemy_units = _build_enemy_units()",
        "-	_sync_units_to_engine()",
        "-	_worker_world_nodes = _build_worker_world_nodes()",
        "-	_enemy_world_nodes = _build_enemy_world_nodes()",
        "-	_worker_ghosts_pending = 0",
        "-	_enemy_ghosts_pending = 0",
        "-	_pending_finish = false",
        "-	_pending_finish_side = """,
        "-	_losing_side = """,
        "-	_apply_layouts()",
        "-	_update_all_unit_ui()",
        "-	_reset_ghost_bars()",
        "-",
        "-",
        "-func _configure_battle_engine() -> void:",
        "-	if _battle_engine == null:",
        "-		return",
        "-	_battle_engine.encouragement_base_gold_cost = encouragement_base_gold_cost",
        "-	_battle_engine.encouragement_cost_growth = encouragement_cost_growth",
        "-	_battle_engine.encouragement_cost_max_gold = encouragement_cost_max_gold",
        "-	_battle_engine.buff_hp_cost_percent = buff_hp_cost_percent",
        "-	_battle_engine.buff_speed_boost_percent = buff_speed_boost_percent",
        "-	_battle_engine.buff_damage_boost_percent = buff_damage_boost_percent",
        "-	_battle_engine.buff_marginal_decay = buff_marginal_decay",
        "-	_battle_engine.buff_max_stacks = buff_max_stacks",
        "-	_battle_engine.unit_damaged.connect(_on_engine_unit_damaged)",
        "-	_battle_engine.unit_died.connect(_on_engine_unit_died)",
        "-	_battle_engine.battle_finished.connect(_on_engine_battle_finished)",
        "-	_battle_engine.unit_progress_updated.connect(_on_engine_unit_progress_updated)",
        "-	_battle_engine.unit_buff_applied.connect(_on_engine_unit_buff_applied)",
        "-",
        "-",
        "-func _sync_units_to_engine() -> void:",
        "-	if _battle_engine == null:",
        "-		return",
        "-	_battle_engine.worker_units.clear()",
        "-	_battle_engine.enemy_units.clear()",
        "-	for unit in _worker_units:",
        "-		var engine_unit: Dictionary = unit.duplicate(true)",
        "-		_battle_engine.worker_units.append(engine_unit)",
        "-	for unit in _enemy_units:",
        "-		var engine_unit: Dictionary = unit.duplicate(true)",
        "-		_battle_engine.enemy_units.append(engine_unit)",
        "-",
        "-",
        "-func _sync_unit_from_engine(unit_uid: int) -> void:",
        "-	if _battle_engine == null:",
        "-		return",
        "-	var engine_unit: Dictionary = _battle_engine.get_unit_by_uid(unit_uid)",
        "-	if engine_unit.is_empty():",
        "-		return",
        "-	var local_unit: Dictionary = _find_local_unit_by_uid(unit_uid)",
        "-	if local_unit.is_empty():",
        "-		return",
        "-	local_unit["hp"] = engine_unit.get("hp", local_unit.get("hp", 0))",
        "-	local_unit["shield"] = engine_unit.get("shield", 0)",
        "-	local_unit["status"] = engine_unit.get("status", "alive")",
        "-	local_unit["progress"] = engine_unit.get("progress", 0.0)",
        "-	if engine_unit.has("temp_buffs"):",
        "-		local_unit["temp_buffs"] = engine_unit.get("temp_buffs").duplicate(true)",
        "-",
        "-",
        "-func _find_local_unit_by_uid(uid: int) -> Dictionary:",
        "-	for unit in _worker_units:",
        "-		if int(unit.get("uid", -1)) == uid:",
        "-			return unit",
        "-	for unit in _enemy_units:",
        "-		if int(unit.get("uid", -1)) == uid:",
        "-			return unit",
        "-	return {}",
        "-",
        "-",
        "-func _on_engine_unit_damaged(unit_uid: int, damage: int, new_hp: int, shield_broken: bool, target_side: String) -> void:",
        "-	var local_unit: Dictionary = _find_local_unit_by_uid(unit_uid)",
        "-	if local_unit.is_empty():",
        "-		return",
        "-	local_unit["hp"] = new_hp",
        "-	local_unit["shield"] = _battle_engine.get_unit_by_uid(unit_uid).get("shield", 0)",
        "-	_update_unit_ui(local_unit)",
        "-	var hp_bar: ProgressBar = local_unit.get("hp_bar") as ProgressBar",
        "-	if hp_bar != null:",
        "-		var max_hp: int = maxi(int(local_unit.get("max_hp", 1)), 1)",
        "-		var prev_hp: int = maxi(new_hp + damage, 0)",
        "-		var prev_ratio: float = clampf(float(prev_hp) / float(max_hp), 0.0, 1.0)",
        "-		_spawn_hp_ghost(target_side, hp_bar, prev_ratio)",
        "-	_play_unit_hit_reaction(local_unit)",
        "-",
        "-",
        "-func _on_engine_unit_died(unit_uid: int, side: String) -> void:",
        "-	var local_unit: Dictionary = _find_local_unit_by_uid(unit_uid)",
        "-	if local_unit.is_empty():",
        "-		return",
        "-	_handle_unit_death(local_unit)",
        "-",
        "-",
        "-func _on_engine_battle_finished(winning_side: String) -> void:",
        "-	_queue_finish(winning_side)",
        "-",
        "-",
        "-func _on_engine_unit_progress_updated(unit_uid: int, progress: float) -> void:",
        "-	var local_unit: Dictionary = _find_local_unit_by_uid(unit_uid)",
        "-	if local_unit.is_empty():",
        "-		return",
        "-	var bar: ProgressBar = local_unit.get("progress_bar")",
        "-	if bar:",
        "-		bar.value = progress",
        "-",
        "-",
        "-func _on_engine_unit_buff_applied(unit_uid: int, buff_type: String, total_speed_percent: float, total_damage_percent: float, stack_count: int) -> void:",
        "-	var local_unit: Dictionary = _find_local_unit_by_uid(unit_uid)",
        "-	if local_unit.is_empty():",
        "-		return",
        "-	if _battle_engine == null:",
        "-		return",
        "-	var engine_unit: Dictionary = _battle_engine.get_unit_by_uid(unit_uid)",
        "-	if engine_unit.has("temp_buffs"):",
        "-		local_unit["temp_buffs"] = engine_unit.get("temp_buffs").duplicate(true)",
        "-	_update_unit_ui(local_unit)",
        "-",
        "-func _update_battle_loop(delta: float) -> void:",
        "-	if hp_overhead_mode:",
        "-		_update_overhead_ui_positions()",
        "-	if _worker_units.size() > 0 and _battle_engine.all_dead(_battle_engine.worker_units):",
        "-		_queue_finish("worker")",
        "-		return",
        "-	if _enemy_units.size() > 0 and _battle_engine.all_dead(_battle_engine.enemy_units):",
        "-		_queue_finish("enemy")",
        "-		return",
        "-	if _pending_finish:",
        "-		return",
        "-	_update_attack_aim_markers(delta)",
        "-	_process_unit_progress(_worker_units, _enemy_units, "enemy", delta)",
        "-	_process_unit_progress(_enemy_units, _worker_units, "worker", delta)",
        "-",
        "-func _process_unit_progress(attacker_units: Array[Dictionary], target_units: Array[Dictionary], target_side: String, delta: float) -> void:",
        "-	if _battle_engine == null:",
        "-		return",
        "-	var ready_attackers: Array[Dictionary] = _battle_engine.update_progress(delta, attacker_units, target_units, target_side)",
        "-	for attack_info in ready_attackers:",
        "-		var unit: Dictionary = attack_info.get("unit", {})",
        "-		var base_damage: int = int(attack_info.get("damage", 0))",
        "-		var damage_boost: float = float(attack_info.get("damage_boost_percent", 0.0))",
        "-		var actual_damage: int = _battle_engine.calculate_actual_damage(base_damage, damage_boost)",
        "-		_spawn_attack_effect(unit, target_units, target_side, actual_damage)",
        "-",
        "-",
        "-func _spawn_attack_effect(attacker: Dictionary, target_units: Array, target_side: String, damage_override: int = -1) -> void:",
        "-	var attacker_actor: BattleActor = attacker.get("actor")",
        "-	if attacker_actor == null:",
        "-		return",
        "-	var attack_effect: AttackEffectDefinition = _resolve_attack_effect(attacker_actor)",
        "-	if attack_effect == null:",
        "-		return",
        "-	_play_unit_attack_animation(attacker)",
        "-	var alive_targets: Array = _get_alive_units(target_units)",
        "-	if alive_targets.is_empty():",
        "-		return",
        "-	_ensure_attack_fx_root()",
        "-	var attack_fx_scene: PackedScene = attack_effect.fx_scene if attack_effect.fx_scene != null else BATTLE_ATTACK_FX_SCENE",
        "-	if _attack_fx_root == null or attack_fx_scene == null:",
        "-		return",
        "-	var spawn_position_local: Vector2 = _get_attack_aim_spawn_position(attacker, alive_targets, target_side)",
        "-	var fx_node: Node = attack_fx_scene.instantiate()",
        "-	if fx_node == null:",
        "-		return",
        "-	_attack_fx_root.add_child(fx_node)",
        "-	if fx_node.has_signal("hit_unit"):",
        "-		fx_node.hit_unit.connect(_on_attack_fx_hit_unit.bind(target_side))",
        "-	if fx_node.has_method("set_allow_multi_hit_per_target"):",
        "-		fx_node.call("set_allow_multi_hit_per_target", attack_effect.allow_multi_hit_per_target)",
        "-	elif attack_effect.allow_multi_hit_per_target:",
        "-		push_warning("Attack FX scene '%s' does not expose allow_multi_hit_per_target; the resource toggle will have no effect." % fx_node.name)",
        "-	var actual_damage: int = damage_override if damage_override >= 0 else attacker_actor.damage",
        "-	if damage_override < 0:",
        "-		var attacker_buffs: Dictionary = attacker.get("temp_buffs", {})",
        "-		var damage_boost: float = float(attacker_buffs.get("damage_boost_percent", 0.0))",
        "-		actual_damage = _battle_engine.calculate_actual_damage(attacker_actor.damage, damage_boost) if _battle_engine else attacker_actor.damage",
        "-	var texture: Texture2D = attack_effect.texture_override if attack_effect.texture_override != null else ATTACK_FX_TEXTURE",
        "-	var hitboxes: Array[Rect2] = attack_effect.fallback_hitboxes.duplicate(true)",
        "-	if hitboxes.is_empty():",
        "-		hitboxes = _get_default_attack_fx_hitboxes()",
        "-	if fx_node.has_method("setup"):",
        "-		fx_node.call(",
        "-			"setup",",
        "-			texture,",
        "-			int(attack_effect.frame_width),",
        "-			int(attack_effect.frame_height),",
        "-			int(attack_effect.frame_count),",
        "-			attack_effect.fps,",
        "-			hitboxes,",
        "-			alive_targets,",
        "-			actual_damage,",
        "-			spawn_position_local,",
        "-			target_side == "enemy",",
        "-			attack_effect.use_scene_hitboxes",
        "-		)",
        "-",
        "-",
        "-func _get_attack_aim_spawn_position(attacker: Dictionary, alive_targets: Array, target_side: String) -> Vector2:",
        "-	var marker_node: Node2D = attacker.get("aim_marker") as Node2D",
        "-	if marker_node != null and is_instance_valid(marker_node):",
        "-		return marker_node.position",
        "-	var spawn_rect: Rect2 = _get_attack_target_spawn_rect(alive_targets)",
        "-	spawn_rect = _clamp_attack_spawn_rect_to_side(spawn_rect, target_side)",
        "-	return _random_point_in_rect(spawn_rect)",
        "-",
        "-",
        "-func _play_unit_attack_animation(unit: Dictionary) -> void:",
        "-	var view: BattleUnitView = unit.get("view") as BattleUnitView",
        "-	if view != null:",
        "-		view.play_attack_animation()",
        "-		return",
        "-	var sprite: AnimatedSprite2D = unit.get("sprite") as AnimatedSprite2D",
        "-	if sprite == null or sprite.sprite_frames == null:",
        "-		return",
        "-	if sprite.sprite_frames.has_animation(&"attack"):",
        "-		sprite.play(&"attack")",
        "-		return",
        "-	if not sprite.sprite_frames.has_animation(&"battle"):",
        "-		return",
        "-	sprite.play(&"battle")",
        "-",
        "-",
        "-func _update_attack_aim_markers(delta: float) -> void:",
        "-	_update_attack_aim_markers_for_side(_worker_units, _enemy_units, "enemy", delta)",
        "-	_update_attack_aim_markers_for_side(_enemy_units, _worker_units, "worker", delta)",
        "-",
        "-",
        "-func _update_attack_aim_markers_for_side(attacker_units: Array, target_units: Array, target_side: String, delta: float) -> void:",
        "-	var alive_targets: Array = _get_alive_units(target_units)",
        "-	var has_targets: bool = not alive_targets.is_empty()",
        "-	for unit in attacker_units:",
        "-		_update_attack_aim_marker(unit, alive_targets, target_side, delta, has_targets)",
        "-",
        "-",
        "-func _update_attack_aim_marker(unit: Dictionary, alive_targets: Array, target_side: String, delta: float, has_targets: bool) -> void:",
        "-	var marker_node: Node2D = unit.get("aim_marker") as Node2D",
        "-	if marker_node == null or not is_instance_valid(marker_node):",
        "-		return",
        "-	if unit.get("status", "alive") != "alive" or int(unit.get("hp", 0)) <= 0:",
        "-		_set_attack_aim_marker_visible(unit, false)",
        "-		return",
        "-	if not has_targets:",
        "-		unit["aim_has_target"] = false",
        "-		unit["aim_target_uid"] = -1",
        "-		_set_attack_aim_marker_visible(unit, false)",
        "-		return",
        "-	if not bool(unit.get("aim_has_target", false)):",
        "-		if not _assign_new_attack_aim_target(unit, alive_targets, true):",
        "-			_set_attack_aim_marker_visible(unit, false)",
        "-			return",
        "-	var target_unit: Dictionary = _find_target_unit_by_uid(alive_targets, int(unit.get("aim_target_uid", -1)))",
        "-	if target_unit.is_empty():",
        "-		if not _assign_new_attack_aim_target(unit, alive_targets, true):",
        "-			_set_attack_aim_marker_visible(unit, false)",
        "-			return",
        "-		target_unit = _find_target_unit_by_uid(alive_targets, int(unit.get("aim_target_uid", -1)))",
        "-		if target_unit.is_empty():",
        "-			_set_attack_aim_marker_visible(unit, false)",
        "-			return",
        "-	var center: Vector2 = _get_unit_orbit_center_local(target_unit)",
        "-	var aim_profile: BattleAimProfile = _resolve_unit_aim_profile(unit)",
        "-	var speed_rad: float = deg_to_rad(maxf(aim_profile.orbit_speed_deg, 0.0))",
        "-	var orbit_dir: float = float(unit.get("aim_orbit_dir", 1.0))",
        "-	unit["aim_orbit_angle"] = float(unit.get("aim_orbit_angle", 0.0)) + speed_rad * orbit_dir * delta",
        "-	var attacker_multiplier: float = _get_unit_aim_radius_multiplier(unit)",
        "-	var target_dodge_factor: float = _get_target_dodge_radius_factor(target_unit)",
        "-	var radius_multiplier: float = attacker_multiplier * target_dodge_factor",
        "-	var orbit_radius_x: float = maxf(float(unit.get("aim_orbit_radius_x", aim_profile.orbit_radius_x)) * radius_multiplier, 1.0)",
        "-	var orbit_radius_y: float = maxf(float(unit.get("aim_orbit_radius_y", aim_profile.orbit_radius_y)) * radius_multiplier, 1.0)",
        "-	var angle: float = float(unit.get("aim_orbit_angle", 0.0))",
        "-	var desired_pos: Vector2 = center + Vector2(cos(angle) * orbit_radius_x, sin(angle) * orbit_radius_y)",
        "-	var max_orbit_radius: float = maxf(orbit_radius_x, orbit_radius_y)",
        "-	var adaptive_move_speed: float = maxf(aim_profile.move_speed, 60.0) * maxf(1.0, max_orbit_radius / 50.0)",
        "-	marker_node.position = marker_node.position.move_toward(desired_pos, adaptive_move_speed * delta)",
        "-	_set_attack_aim_marker_visible(unit, true)",
        "-",
        "-",
        "-func _assign_new_attack_aim_target(unit: Dictionary, alive_targets: Array, snap_marker_to_orbit: bool = false) -> bool:",
        "-	if alive_targets.is_empty():",
        "-		unit["aim_has_target"] = false",
        "-		unit["aim_target_uid"] = -1",
        "-		return false",
        "-	var marker_node: Node2D = unit.get("aim_marker") as Node2D",
        "-	if marker_node == null or not is_instance_valid(marker_node):",
        "-		unit["aim_has_target"] = false",
        "-		unit["aim_target_uid"] = -1",
        "-		return false",
        "-	var attacker_origin: Vector2 = _get_unit_attack_origin_local(unit)",
        "-	var best_target: Dictionary = {}",
        "-	var best_dist_sq: float = INF",
        "-	for target in alive_targets:",
        "-		if not (target is Dictionary):",
        "-			continue",
        "-		var target_data: Dictionary = target as Dictionary",
        "-		var center: Vector2 = _get_unit_orbit_center_local(target_data)",
        "-		var dist_sq: float = attacker_origin.distance_squared_to(center)",
        "-		if dist_sq < best_dist_sq:",
        "-			best_dist_sq = dist_sq",
        "-			best_target = target_data",
        "-	if best_target.is_empty():",
        "-		unit["aim_has_target"] = false",
        "-		unit["aim_target_uid"] = -1",
        "-		return false",
        "-	unit["aim_target_uid"] = int(best_target.get("uid", -1))",
        "-	unit["aim_has_target"] = true",
        "-	var aim_profile: BattleAimProfile = _resolve_unit_aim_profile(unit)",
        "-	unit["aim_orbit_angle"] = randf() * TAU",
        "-	unit["aim_orbit_dir"] = -1.0 if randf() < 0.5 else 1.0",
        "-	var radius_jitter_x: float = randf_range(-aim_profile.orbit_radius_jitter_x, aim_profile.orbit_radius_jitter_x)",
        "-	var radius_jitter_y: float = randf_range(-aim_profile.orbit_radius_jitter_y, aim_profile.orbit_radius_jitter_y)",
        "-	unit["aim_orbit_radius_x"] = maxf(aim_profile.orbit_radius_x + radius_jitter_x, 2.0)",
        "-	unit["aim_orbit_radius_y"] = maxf(aim_profile.orbit_radius_y + radius_jitter_y, 2.0)",
        "-	if snap_marker_to_orbit:",
        "-		var center: Vector2 = _get_unit_orbit_center_local(best_target)",
        "-		var angle: float = float(unit.get("aim_orbit_angle", 0.0))",
        "-		var attacker_multiplier: float = _get_unit_aim_radius_multiplier(unit)",
        "-		var target_dodge_factor: float = _get_target_dodge_radius_factor(best_target)",
        "-		var radius_multiplier: float = attacker_multiplier * target_dodge_factor",
        "-		var radius_x: float = float(unit.get("aim_orbit_radius_x", aim_profile.orbit_radius_x)) * radius_multiplier",
        "-		var radius_y: float = float(unit.get("aim_orbit_radius_y", aim_profile.orbit_radius_y)) * radius_multiplier",
        "-		marker_node.position = center + Vector2(cos(angle) * radius_x, sin(angle) * radius_y)",
        "-	return true",
        "-",
        "-",
        "-func _find_target_unit_by_uid(units: Array, target_uid: int) -> Dictionary:",
        "-	if target_uid < 0:",
        "-		return {}",
        "-	for target in units:",
        "-		if not (target is Dictionary):",
        "-			continue",
        "-		var target_data: Dictionary = target as Dictionary",
        "-		if int(target_data.get("uid", -1)) == target_uid:",
        "-			return target_data",
