        "-",
        "-func _get_unit_orbit_center_local(unit: Dictionary) -> Vector2:",
        "-	var hurtbox_rect: Rect2 = _get_unit_hurtbox_rect(unit)",
        "-	var center_offset: Vector2 = _get_unit_orbit_center_offset_local(unit)",
        "-	if hurtbox_rect.size.x > 0.0 and hurtbox_rect.size.y > 0.0:",
        "-		return hurtbox_rect.get_center() + center_offset",
        "-	return _get_unit_attack_origin_local(unit) + center_offset",
