        "-",
        "-func _get_unit_orbit_center_offset_local(unit: Dictionary) -> Vector2:",
        "-	var actor: BattleActor = unit.get("actor") as BattleActor",
        "-	var offset: Vector2 = Vector2.ZERO",
        "-	if actor != null:",
        "-		offset += actor.battle_aim_orbit_center_offset",
        "-	offset *= battle_sprite_scale.abs()",
        "-	if String(unit.get("side", "worker")) == "enemy":",
        "-		offset.x = -offset.x",
