        "-func _get_alive_units(units: Array) -> Array:",
        "-	var result: Array = []",
        "-	for unit in units:",
        "-		if not (unit is Dictionary):",
        "-			continue",
        "-		var unit_data: Dictionary = unit as Dictionary",
        "-		if int(unit_data.get("hp", 0)) <= 0:",
        "-			continue",
        "-		if String(unit_data.get("status", "alive")) != "alive":",
