        "+	get_node_or_null("EnemiesMarkers/Marker1") as Marker2D,",
        "+	get_node_or_null("EnemiesMarkers/Marker2") as Marker2D,",
        "+	get_node_or_null("EnemiesMarkers/Marker3") as Marker2D,",
        "+	get_node_or_null("EnemiesMarkers/Marker4") as Marker2D",
        "+]",
