        "+var _desired_enemy_count: int = 1",
        "+var _worker_ghosts_pending: int = 0",
        "+var _enemy_ghosts_pending: int = 0",
        "+var _worker_death_fades_pending: int = 0",
        "+var _enemy_death_fades_pending: int = 0",
