        "+func _sync_units_to_engine() -> void:",
        "+	if _battle_engine == null:",
        "+		return",
        "+	_battle_engine.worker_units.clear()",
        "+	_battle_engine.enemy_units.clear()",
        "+	for unit in _worker_units:",
        "+		var engine_unit: Dictionary = unit.duplicate(true)",
        "+		_battle_engine.worker_units.append(engine_unit)",
        "+	for unit in _enemy_units:",
        "+		var engine_unit: Dictionary = unit.duplicate(true)",
        "+		_battle_engine.enemy_units.append(engine_unit)",
        "+",
        "+",
        "+func _sync_unit_from_engine(unit_uid: int) -> void:",
        "+	if _battle_engine == null:",
        "+		return",
        "+	var engine_unit: Dictionary = _battle_engine.get_unit_by_uid(unit_uid)",
        "+	if engine_unit.is_empty():",
        "+		return",
        "+	var local_unit: Dictionary = _find_local_unit_by_uid(unit_uid)",
        "+	if local_unit.is_empty():",
        "+		return",
        "+	local_unit["hp"] = engine_unit.get("hp", local_unit.get("hp", 0))",
        "+	local_unit["shield"] = engine_unit.get("shield", 0)",
        "+	local_unit["status"] = engine_unit.get("status", "alive")",
        "+	local_unit["progress"] = engine_unit.get("progress", 0.0)",
        "+	if engine_unit.has("temp_buffs"):",
        "+		local_unit["temp_buffs"] = engine_unit.get("temp_buffs").duplicate(true)",
        "+",
        "+",
        "+func _find_local_unit_by_uid(uid: int) -> Dictionary:",
        "+	for unit in _worker_units:",
        "+		if int(unit.get("uid", -1)) == uid:",
        "+			return unit",
        "+	for unit in _enemy_units:",
        "+		if int(unit.get("uid", -1)) == uid:",
        "+			return unit",
        "+	return {}",
        "+",
        "+",
        "+func _on_engine_unit_damaged(unit_uid: int, damage: int, new_hp: int, shield_broken: bool, target_side: String) -> void:",
        "+	var local_unit: Dictionary = _find_local_unit_by_uid(unit_uid)",
        "+	if local_unit.is_empty():",
        "+		return",
        "+	local_unit["hp"] = new_hp",
        "+	local_unit["shield"] = _battle_engine.get_unit_by_uid(unit_uid).get("shield", 0)",
        "+	_update_unit_ui(local_unit)",
        "+	var hp_bar: ProgressBar = local_unit.get("hp_bar") as ProgressBar",
        "+	if hp_bar != null:",
        "+		var max_hp: int = maxi(int(local_unit.get("max_hp", 1)), 1)",
        "+		var prev_hp: int = maxi(new_hp + damage, 0)",
        "+		var prev_ratio: float = clampf(float(prev_hp) / float(max_hp), 0.0, 1.0)",
        "+		_spawn_hp_ghost(target_side, hp_bar, prev_ratio)",
        "+	_play_unit_hit_reaction(local_unit)",
        "+",
        "+",
        "+func _on_engine_unit_died(unit_uid: int, side: String) -> void:",
        "+	var local_unit: Dictionary = _find_local_unit_by_uid(unit_uid)",
        "+	if local_unit.is_empty():",
        "+		return",
        "+	_handle_unit_death(local_unit)",
        "+",
        "+",
        "+func _on_engine_battle_finished(winning_side: String) -> void:",
        "+	_queue_finish(winning_side)",
        "+",
        "+",
        "+func _on_engine_unit_progress_updated(unit_uid: int, progress: float) -> void:",
        "+	var local_unit: Dictionary = _find_local_unit_by_uid(unit_uid)",
        "+	if local_unit.is_empty():",
        "+		return",
        "+	var bar: ProgressBar = local_unit.get("progress_bar")",
        "+	if bar:",
        "+		bar.value = progress",
        "+",
        "+",
        "+func _on_engine_unit_buff_applied(unit_uid: int, buff_type: String, total_speed_percent: float, total_damage_percent: float, stack_count: int) -> void:",
        "+	var local_unit: Dictionary = _find_local_unit_by_uid(unit_uid)",
        "+	if local_unit.is_empty():",
        "+		return",
        "+	if _battle_engine == null:",
        "+		return",
        "+	var engine_unit: Dictionary = _battle_engine.get_unit_by_uid(unit_uid)",
        "+	if engine_unit.has("temp_buffs"):",
        "+		local_unit["temp_buffs"] = engine_unit.get("temp_buffs").duplicate(true)",
        "+	_update_unit_ui(local_unit)",
        "+",
        "+func _update_battle_loop(delta: float) -> void:",
        "+	if hp_overhead_mode:",
        "+		_update_overhead_ui_positions()",
        "+	if _worker_units.size() > 0 and _battle_engine.all_dead(_battle_engine.worker_units):",
        "+		_queue_finish("worker")",
        "+		return",
        "+	if _enemy_units.size() > 0 and _battle_engine.all_dead(_battle_engine.enemy_units):",
        "+		_queue_finish("enemy")",
        "+		return",
        "+	if _pending_finish:",
        "+		return",
        "+	_update_attack_aim_markers(delta)",
        "+	_process_unit_progress(_worker_units, _enemy_units, "enemy", delta)",
        "+	_process_unit_progress(_enemy_units, _worker_units, "worker", delta)",
        "+",
        "+func _process_unit_progress(attacker_units: Array[Dictionary], target_units: Array[Dictionary], target_side: String, delta: float) -> void:",
        "+	if _battle_engine == null:",
        "+		return",
        "+	var ready_attackers: Array[Dictionary] = _battle_engine.update_progress(delta, attacker_units, target_units, target_side)",
        "+	for attack_info in ready_attackers:",
        "+		var unit: Dictionary = attack_info.get("unit", {})",
        "+		var base_damage: int = int(attack_info.get("damage", 0))",
        "+		var damage_boost: float = float(attack_info.get("damage_boost_percent", 0.0))",
        "+		var actual_damage: int = _battle_engine.calculate_actual_damage(base_damage, damage_boost)",
        "+		_spawn_attack_effect(unit, target_units, target_side, actual_damage)",
        "+",
        "+",
        "+func _spawn_attack_effect(attacker: Dictionary, target_units: Array, target_side: String, damage_override: int = -1) -> void:",
        "+	var attacker_actor: BattleActor = attacker.get("actor")",
        "+	if attacker_actor == null:",
        "+		return",
        "+	var attack_effect: AttackEffectDefinition = _resolve_attack_effect(attacker_actor)",
        "+	if attack_effect == null:",
        "+		return",
        "+	_play_unit_attack_animation(attacker)",
        "+	var alive_targets: Array = _get_alive_units(target_units)",
        "+	if alive_targets.is_empty():",
        "+		return",
        "+	_ensure_attack_fx_root()",
        "+	var attack_fx_scene: PackedScene = attack_effect.fx_scene if attack_effect.fx_scene != null else BATTLE_ATTACK_FX_SCENE",
        "+	if _attack_fx_root == null or attack_fx_scene == null:",
        "+		return",
        "+	var spawn_position_local: Vector2 = _get_attack_aim_spawn_position(attacker, alive_targets, target_side)",
        "+	var fx_node: Node = attack_fx_scene.instantiate()",
        "+	if fx_node == null:",
        "+		return",
        "+	_attack_fx_root.add_child(fx_node)",
        "+	if fx_node.has_signal("hit_unit"):",
        "+		fx_node.hit_unit.connect(_on_attack_fx_hit_unit.bind(target_side))",
        "+	if fx_node.has_method("set_allow_multi_hit_per_target"):",
        "+		fx_node.call("set_allow_multi_hit_per_target", attack_effect.allow_multi_hit_per_target)",
        "+	elif attack_effect.allow_multi_hit_per_target:",
        "+		push_warning("Attack FX scene '%s' does not expose allow_multi_hit_per_target; the resource toggle will have no effect." % fx_node.name)",
        "+	var actual_damage: int = damage_override if damage_override >= 0 else attacker_actor.damage",
        "+	if damage_override < 0:",
        "+		var attacker_buffs: Dictionary = attacker.get("temp_buffs", {})",
        "+		var damage_boost: float = float(attacker_buffs.get("damage_boost_percent", 0.0))",
        "+		actual_damage = _battle_engine.calculate_actual_damage(attacker_actor.damage, damage_boost) if _battle_engine else attacker_actor.damage",
        "+	var texture: Texture2D = attack_effect.texture_override if attack_effect.texture_override != null else ATTACK_FX_TEXTURE",
        "+	var hitboxes: Array[Rect2] = attack_effect.fallback_hitboxes.duplicate(true)",
        "+	if hitboxes.is_empty():",
        "+		hitboxes = _get_default_attack_fx_hitboxes()",
        "+	if fx_node.has_method("setup"):",
        "+		fx_node.call(",
        "+			"setup",",
        "+			texture,",
        "+			int(attack_effect.frame_width),",
        "+			int(attack_effect.frame_height),",
        "+			int(attack_effect.frame_count),",
        "+			attack_effect.fps,",
        "+			hitboxes,",
        "+			alive_targets,",
        "+			actual_damage,",
        "+			spawn_position_local,",
        "+			target_side == "enemy",",
        "+			attack_effect.use_scene_hitboxes",
        "+		)",
        "+",
        "+",
        "+func _get_attack_aim_spawn_position(attacker: Dictionary, alive_targets: Array, target_side: String) -> Vector2:",
        "+	var marker_node: Node2D = attacker.get("aim_marker") as Node2D",
        "+	if marker_node != null and is_instance_valid(marker_node):",
        "+		return marker_node.position",
        "+	var spawn_rect: Rect2 = _get_attack_target_spawn_rect(alive_targets)",
        "+	spawn_rect = _clamp_attack_spawn_rect_to_side(spawn_rect, target_side)",
        "+	return _random_point_in_rect(spawn_rect)",
        "+",
        "+",
        "+func _play_unit_attack_animation(unit: Dictionary) -> void:",
        "+	var view: BattleUnitView = unit.get("view") as BattleUnitView",
        "+	if view != null:",
        "+		view.play_attack_animation()",
        "+		return",
        "+	var sprite: AnimatedSprite2D = unit.get("sprite") as AnimatedSprite2D",
        "+	if sprite == null or sprite.sprite_frames == null:",
        "+		return",
        "+	if sprite.sprite_frames.has_animation(&"attack"):",
        "+		sprite.play(&"attack")",
        "+		return",
        "+	if not sprite.sprite_frames.has_animation(&"battle"):",
        "+		return",
        "+	sprite.play(&"battle")",
        "+",
        "+",
        "+func _update_attack_aim_markers(delta: float) -> void:",
        "+	_update_attack_aim_markers_for_side(_worker_units, _enemy_units, "enemy", delta)",
        "+	_update_attack_aim_markers_for_side(_enemy_units, _worker_units, "worker", delta)",
        "+",
        "+",
        "+func _update_attack_aim_markers_for_side(attacker_units: Array, target_units: Array, target_side: String, delta: float) -> void:",
        "+	var alive_targets: Array = _get_alive_units(target_units)",
        "+	var has_targets: bool = not alive_targets.is_empty()",
        "+	for unit in attacker_units:",
        "+		_update_attack_aim_marker(unit, alive_targets, target_side, delta, has_targets)",
        "+",
        "+",
        "+func _update_attack_aim_marker(unit: Dictionary, alive_targets: Array, target_side: String, delta: float, has_targets: bool) -> void:",
        "+	var marker_node: Node2D = unit.get("aim_marker") as Node2D",
        "+	if marker_node == null or not is_instance_valid(marker_node):",
        "+		return",
        "+	if unit.get("status", "alive") != "alive" or int(unit.get("hp", 0)) <= 0:",
        "+		_set_attack_aim_marker_visible(unit, false)",
        "+		return",
        "+	if not has_targets:",
        "+		unit["aim_has_target"] = false",
        "+		unit["aim_target_uid"] = -1",
        "+		_set_attack_aim_marker_visible(unit, false)",
        "+		return",
        "+	if not bool(unit.get("aim_has_target", false)):",
        "+		if not _assign_new_attack_aim_target(unit, alive_targets, true):",
        "+			_set_attack_aim_marker_visible(unit, false)",
        "+			return",
        "+	var target_unit: Dictionary = _find_target_unit_by_uid(alive_targets, int(unit.get("aim_target_uid", -1)))",
        "+	if target_unit.is_empty():",
        "+		if not _assign_new_attack_aim_target(unit, alive_targets, true):",
        "+			_set_attack_aim_marker_visible(unit, false)",
        "+			return",
        "+		target_unit = _find_target_unit_by_uid(alive_targets, int(unit.get("aim_target_uid", -1)))",
        "+		if target_unit.is_empty():",
        "+			_set_attack_aim_marker_visible(unit, false)",
        "+			return",
        "+	var center: Vector2 = _get_unit_orbit_center_local(target_unit)",
        "+	var aim_profile: BattleAimProfile = _resolve_unit_aim_profile(unit)",
        "+	var speed_rad: float = deg_to_rad(maxf(aim_profile.orbit_speed_deg, 0.0))",
        "+	var orbit_dir: float = float(unit.get("aim_orbit_dir", 1.0))",
        "+	unit["aim_orbit_angle"] = float(unit.get("aim_orbit_angle", 0.0)) + speed_rad * orbit_dir * delta",
        "+	var attacker_multiplier: float = _get_unit_aim_radius_multiplier(unit)",
        "+	var target_dodge_factor: float = _get_target_dodge_radius_factor(target_unit)",
        "+	var radius_multiplier: float = attacker_multiplier * target_dodge_factor",
        "+	var orbit_radius_x: float = maxf(float(unit.get("aim_orbit_radius_x", aim_profile.orbit_radius_x)) * radius_multiplier, 1.0)",
        "+	var orbit_radius_y: float = maxf(float(unit.get("aim_orbit_radius_y", aim_profile.orbit_radius_y)) * radius_multiplier, 1.0)",
        "+	var angle: float = float(unit.get("aim_orbit_angle", 0.0))",
        "+	var desired_pos: Vector2 = center + Vector2(cos(angle) * orbit_radius_x, sin(angle) * orbit_radius_y)",
        "+	var max_orbit_radius: float = maxf(orbit_radius_x, orbit_radius_y)",
        "+	var adaptive_move_speed: float = maxf(aim_profile.move_speed, 60.0) * maxf(1.0, max_orbit_radius / 50.0)",
        "+	marker_node.position = marker_node.position.move_toward(desired_pos, adaptive_move_speed * delta)",
        "+	_set_attack_aim_marker_visible(unit, true)",
        "+",
        "+",
        "+func _assign_new_attack_aim_target(unit: Dictionary, alive_targets: Array, snap_marker_to_orbit: bool = false) -> bool:",
        "+	if alive_targets.is_empty():",
        "+		unit["aim_has_target"] = false",
        "+		unit["aim_target_uid"] = -1",
        "+		return false",
        "+	var marker_node: Node2D = unit.get("aim_marker") as Node2D",
        "+	if marker_node == null or not is_instance_valid(marker_node):",
        "+		unit["aim_has_target"] = false",
        "+		unit["aim_target_uid"] = -1",
        "+		return false",
        "+	var attacker_origin: Vector2 = _get_unit_attack_origin_local(unit)",
        "+	var best_target: Dictionary = {}",
        "+	var best_dist_sq: float = INF",
        "+	for target in alive_targets:",
        "+		if not (target is Dictionary):",
        "+			continue",
        "+		var target_data: Dictionary = target as Dictionary",
        "+		var center: Vector2 = _get_unit_orbit_center_local(target_data)",
        "+		var dist_sq: float = attacker_origin.distance_squared_to(center)",
        "+		if dist_sq < best_dist_sq:",
        "+			best_dist_sq = dist_sq",
        "+			best_target = target_data",
        "+	if best_target.is_empty():",
        "+		unit["aim_has_target"] = false",
        "+		unit["aim_target_uid"] = -1",
        "+		return false",
        "+	unit["aim_target_uid"] = int(best_target.get("uid", -1))",
        "+	unit["aim_has_target"] = true",
        "+	var aim_profile: BattleAimProfile = _resolve_unit_aim_profile(unit)",
        "+	unit["aim_orbit_angle"] = randf() * TAU",
        "+	unit["aim_orbit_dir"] = -1.0 if randf() < 0.5 else 1.0",
        "+	var radius_jitter_x: float = randf_range(-aim_profile.orbit_radius_jitter_x, aim_profile.orbit_radius_jitter_x)",
        "+	var radius_jitter_y: float = randf_range(-aim_profile.orbit_radius_jitter_y, aim_profile.orbit_radius_jitter_y)",
        "+	unit["aim_orbit_radius_x"] = maxf(aim_profile.orbit_radius_x + radius_jitter_x, 2.0)",
        "+	unit["aim_orbit_radius_y"] = maxf(aim_profile.orbit_radius_y + radius_jitter_y, 2.0)",
        "+	if snap_marker_to_orbit:",
        "+		var center: Vector2 = _get_unit_orbit_center_local(best_target)",
        "+		var angle: float = float(unit.get("aim_orbit_angle", 0.0))",
        "+		var attacker_multiplier: float = _get_unit_aim_radius_multiplier(unit)",
        "+		var target_dodge_factor: float = _get_target_dodge_radius_factor(best_target)",
        "+		var radius_multiplier: float = attacker_multiplier * target_dodge_factor",
        "+		var radius_x: float = float(unit.get("aim_orbit_radius_x", aim_profile.orbit_radius_x)) * radius_multiplier",
        "+		var radius_y: float = float(unit.get("aim_orbit_radius_y", aim_profile.orbit_radius_y)) * radius_multiplier",
        "+		marker_node.position = center + Vector2(cos(angle) * radius_x, sin(angle) * radius_y)",
        "+	return true",
        "+",
        "+",
        "+func _find_target_unit_by_uid(units: Array, target_uid: int) -> Dictionary:",
        "+	if target_uid < 0:",
        "+		return {}",
        "+	for target in units:",
        "+		if not (target is Dictionary):",
        "+			continue",
        "+		var target_data: Dictionary = target as Dictionary",
        "+		if int(target_data.get("uid", -1)) == target_uid:",
        "+			return target_data",
        "+	return {}",
        "+",
        "+",
        "+func _get_unit_orbit_center_local(unit: Dictionary) -> Vector2:",
        "+	var hurtbox_rect: Rect2 = _get_unit_hurtbox_rect(unit)",
        "+	var center_offset: Vector2 = _get_unit_orbit_center_offset_local(unit)",
        "+	if hurtbox_rect.size.x > 0.0 and hurtbox_rect.size.y > 0.0:",
        "+		return hurtbox_rect.get_center() + center_offset",
        "+	return _get_unit_attack_origin_local(unit) + center_offset",
        "+",
        "+",
        "+func _get_unit_orbit_center_offset_local(unit: Dictionary) -> Vector2:",
        "+	var actor: BattleActor = unit.get("actor") as BattleActor",
        "+	var offset: Vector2 = Vector2.ZERO",
        "+	if actor != null:",
        "+		offset += actor.battle_aim_orbit_center_offset",
        "+	offset *= battle_sprite_scale.abs()",
        "+	if String(unit.get("side", "worker")) == "enemy":",
        "+		offset.x = -offset.x",
        "+	return offset",
        "+",
        "+",
        "+func _get_unit_attack_origin_local(unit: Dictionary) -> Vector2:",
        "+	var marker: Marker2D = unit.get("marker") as Marker2D",
        "+	if marker == null:",
        "+		return Vector2.ZERO",
        "+	var pos: Vector2 = marker.global_position",
        "+	if _attack_fx_root != null and is_instance_valid(_attack_fx_root):",
        "+		pos = _attack_fx_root.to_local(pos)",
        "+	return pos",
        "+",
        "+",
        "+func _get_unit_aim_radius_multiplier(unit: Dictionary) -> float:",
        "+	if String(unit.get("side", "worker")) != "enemy":",
        "+		return 1.0",
        "+	if GameEvents == null or not GameEvents.has_method("get_enemy_aim_radius_multiplier"):",
        "+		return 1.0",
        "+	return maxf(float(GameEvents.get_enemy_aim_radius_multiplier()), 1.0)",
        "+",
        "+",
        "+func _get_target_dodge_radius_factor(target_unit: Dictionary) -> float:",
        "+	var actor: BattleActor = target_unit.get("actor")",
        "+	if actor == null:",
        "+		return 1.0",
        "+	var base_factor: float = maxf(actor.dodge_aim_radius_factor, 0.1)",
        "+	var temp_buffs: Dictionary = target_unit.get("temp_buffs", {})",
        "+	var dodge_multiplier: float = 1.0 + float(temp_buffs.get("dodge_radius_percent", 0.0))",
        "+	var factor: float = base_factor * dodge_multiplier",
        "+	return minf(factor, 3.0)",
        "+",
        "+",
        "+func _set_attack_aim_marker_visible(unit: Dictionary, visible_value: bool) -> void:",
        "+	var marker_node: CanvasItem = unit.get("aim_marker") as CanvasItem",
        "+	if marker_node == null or not is_instance_valid(marker_node):",
        "+		return",
        "+	marker_node.visible = visible_value",
        "+",
        "+",
        "+func _update_attack_aim_marker_visibility(unit: Dictionary, assume_targets_exist: bool = false) -> void:",
        "+	var should_show: bool = unit.get("status", "alive") == "alive" and int(unit.get("hp", 0)) > 0",
        "+	if should_show and not assume_targets_exist:",
        "+		var target_side: String = "enemy" if String(unit.get("side", "worker")) == "worker" else "worker"",
        "+		var targets: Array = _get_alive_units(_enemy_units if target_side == "enemy" else _worker_units)",
        "+		should_show = not targets.is_empty()",
        "+	_set_attack_aim_marker_visible(unit, should_show)",
        "+",
        "+",
        "+func _on_attack_fx_hit_unit(unit_uid: int, damage: int, target_side: String) -> void:",
        "+	if _battle_engine == null:",
        "+		return",
        "+	_battle_engine.apply_damage(unit_uid, damage, target_side)",
        "+",
        "+",
        "+func _play_unit_hit_reaction(target: Dictionary) -> void:",
        "+	if target.is_empty():",
        "+		return",
        "+	var view: BattleUnitView = target.get("view") as BattleUnitView",
        "+	if view != null and is_instance_valid(view):",
        "+		view.play_hit_reaction()",
        "+",
        "+",
        "+func _get_alive_units(units: Array) -> Array:",
        "+	var result: Array = []",
        "+	for unit in units:",
        "+		if not (unit is Dictionary):",
        "+			continue",
        "+		var unit_data: Dictionary = unit as Dictionary",
        "+		if int(unit_data.get("hp", 0)) <= 0:",
        "+			continue",
        "+		if String(unit_data.get("status", "alive")) != "alive":",
        "+			continue",
        "+		result.append(unit_data)",
        "+	return result",
        "+",
        "+",
        "+func _get_attack_target_spawn_rect(target_units: Array) -> Rect2:",
        "+	var combined: Rect2 = Rect2()",
        "+	var has_rect: bool = false",
        "+	for unit in target_units:",
        "+		if not (unit is Dictionary):",
        "+			continue",
        "+		var target_rect: Rect2 = _get_unit_attack_target_rect(unit as Dictionary)",
        "+		if target_rect.size.x <= 0.0 or target_rect.size.y <= 0.0:",
        "+			continue",
        "+		if not has_rect:",
        "+			combined = target_rect",
        "+			has_rect = true",
        "+		else:",
        "+			combined = combined.merge(target_rect)",
        "+	if not has_rect:",
        "+		return Rect2(Vector2.ZERO, maxf(attack_fx_min_spawn_size.x, 1.0) * Vector2.RIGHT + maxf(attack_fx_min_spawn_size.y, 1.0) * Vector2.DOWN)",
        "+	combined = combined.grow_individual(attack_fx_target_padding.x, attack_fx_target_padding.y, attack_fx_target_padding.x, attack_fx_target_padding.y)",
        "+	if combined.size.x < attack_fx_min_spawn_size.x:",
        "+		combined.position.x -= (attack_fx_min_spawn_size.x - combined.size.x) * 0.5",
        "+		combined.size.x = attack_fx_min_spawn_size.x",
        "+	if combined.size.y < attack_fx_min_spawn_size.y:",
        "+		combined.position.y -= (attack_fx_min_spawn_size.y - combined.size.y) * 0.5",
        "+		combined.size.y = attack_fx_min_spawn_size.y",
        "+	return combined",
        "+",
        "+",
        "+func _random_point_in_rect(rect: Rect2) -> Vector2:",
        "+	if rect.size.x <= 0.0 or rect.size.y <= 0.0:",
        "+		return rect.position",
        "+	return Vector2(",
        "+		randf_range(rect.position.x, rect.position.x + rect.size.x),",
        "+		randf_range(rect.position.y, rect.position.y + rect.size.y)",
        "+	)",
        "+",
        "+",
        "+func _clamp_attack_spawn_rect_to_side(rect: Rect2, target_side: String) -> Rect2:",
        "+	var battle_rect: Rect2 = Rect2(Vector2.ZERO, battle_box_size)",
        "+	var mid_x: float = battle_rect.position.x + battle_rect.size.x * 0.5",
        "+	var side_rect: Rect2 = battle_rect",
        "+	if target_side == "enemy":",
        "+		side_rect.position.x = mid_x",
        "+		side_rect.size.x = maxf(battle_rect.size.x - (mid_x - battle_rect.position.x), 1.0)",
        "+	else:",
        "+		side_rect.size.x = maxf(mid_x - battle_rect.position.x, 1.0)",
        "+",
        "+	var left: float = clampf(rect.position.x, side_rect.position.x, side_rect.position.x + side_rect.size.x)",
        "+	var top: float = clampf(rect.position.y, side_rect.position.y, side_rect.position.y + side_rect.size.y)",
        "+	var right: float = clampf(rect.position.x + rect.size.x, side_rect.position.x, side_rect.position.x + side_rect.size.x)",
        "+	var bottom: float = clampf(rect.position.y + rect.size.y, side_rect.position.y, side_rect.position.y + side_rect.size.y)",
        "+	var width: float = maxf(right - left, minf(attack_fx_min_spawn_size.x, side_rect.size.x))",
        "+	var height: float = maxf(bottom - top, minf(attack_fx_min_spawn_size.y, side_rect.size.y))",
        "+	left = clampf(left, side_rect.position.x, side_rect.position.x + side_rect.size.x - width)",
        "+	top = clampf(top, side_rect.position.y, side_rect.position.y + side_rect.size.y - height)",
        "+	return Rect2(Vector2(left, top), Vector2(width, height))",
        "+",
        "+",
        "+func _get_unit_hurtbox_rect(unit: Dictionary) -> Rect2:",
        "+	var hurtbox_shapes: Array[CollisionShape2D] = _get_unit_hurtbox_shapes(unit)",
        "+	var union_rect: Rect2 = Rect2()",
        "+	var has_union: bool = false",
        "+	for hurtbox_shape in hurtbox_shapes:",
        "+		var shape_rect: Rect2 = _shape_to_target_space_rect(hurtbox_shape)",
        "+		if shape_rect.size.x <= 0.0 or shape_rect.size.y <= 0.0:",
        "+			continue",
        "+		if not has_union:",
        "+			union_rect = shape_rect",
        "+			has_union = true",
        "+		else:",
        "+			union_rect = union_rect.merge(shape_rect)",
        "+	return union_rect if has_union else Rect2()",
        "+",
        "+",
        "+func _get_unit_attack_target_rect(unit: Dictionary) -> Rect2:",
        "+	var marker: Marker2D = unit.get("marker") as Marker2D",
        "+	var actor: BattleActor = unit.get("actor") as BattleActor",
        "+	if marker == null or actor == null:",
        "+		return _get_unit_hurtbox_rect(unit)",
        "+	var feet_pos: Vector2 = marker.global_position",
        "+	if _attack_fx_root != null and is_instance_valid(_attack_fx_root):",
        "+		feet_pos = _attack_fx_root.to_local(feet_pos)",
        "+	var frame_size: Vector2 = _get_actor_battle_frame_size(actor) * battle_sprite_scale.abs()",
        "+	if frame_size == Vector2.ZERO:",
        "+		return _get_unit_hurtbox_rect(unit)",
        "+	var width: float = maxf(frame_size.x * 0.7, 24.0)",
        "+	var height: float = maxf(frame_size.y * 0.3, 20.0)",
        "+	var left: float = feet_pos.x - width * 0.5",
        "+	var top: float = feet_pos.y - frame_size.y * 0.45",
        "+	return Rect2(Vector2(left, top), Vector2(width, height))",
        "+",
        "+",
        "+func _get_default_attack_fx_hitboxes() -> Array[Rect2]:",
        "+	return [",
        "+		Rect2(),",
        "+		Rect2(-18.0, -10.0, 26.0, 18.0),",
        "+		Rect2(-10.0, -12.0, 38.0, 22.0),",
        "+		Rect2(-4.0, -12.0, 42.0, 22.0),",
        "+		Rect2(4.0, -10.0, 30.0, 18.0),",
        "+		Rect2(),",
        "+	]",
        "+",
        "+",
        "+func _resolve_attack_effect(actor: BattleActor) -> AttackEffectDefinition:",
        "+	if actor != null and actor.attack_effect != null:",
        "+		return actor.attack_effect",
        "+	if default_attack_effect != null:",
        "+		return default_attack_effect",
        "+	return DEFAULT_ATTACK_EFFECT",
        "+",
        "+",
        "+func _resolve_unit_aim_profile(unit: Dictionary) -> BattleAimProfile:",
        "+	var actor: BattleActor = unit.get("actor") as BattleActor",
        "+	if actor != null and actor.battle_aim_profile != null:",
        "+		return actor.battle_aim_profile",
        "+	if default_battle_aim_profile != null:",
        "+		return default_battle_aim_profile",
        "+	return DEFAULT_BATTLE_AIM_PROFILE",
        "+",
        "+",
        "+func _find_worker_unit_by_actor(actor: BattleActor) -> Dictionary:",
        "+	if actor == null:",
        "+		return {}",
        "+	for unit in _worker_units:",
        "+		if not (unit is Dictionary):",
        "+			continue",
        "+		var unit_data: Dictionary = unit as Dictionary",
        "+		if unit_data.get("actor") == actor:",
        "+			return unit_data",
        "+	return {}",
        "+",
        "+",
        "+func _sync_unit_hp_to_global(unit: Dictionary) -> void:",
        "+	if Engine.is_editor_hint():",
        "+		return",
        "+	if String(unit.get("side", "")) != "worker":",
        "+		return",
        "+	var actor: BattleActor = unit.get("actor")",
        "+	if actor == null:",
        "+		return",
        "+	if GameEvents.has_method("set_actor_hp"):",
        "+		GameEvents.set_actor_hp(actor, int(unit.get("hp", 0)))",
        "+",
        "+func _handle_unit_death(unit: Dictionary) -> void:",
        "+	if unit.get("status", "alive") != "alive":",
        "+		return",
        "+	unit["status"] = "down"",
        "+	_disable_unit_hurtbox(unit)",
        "+	_set_attack_aim_marker_visible(unit, false)",
        "+	var side: String = String(unit.get("side", ""))",
        "+	var sprite: CanvasItem = unit.get("sprite")",
        "+	var progress_bar: ProgressBar = unit.get("progress_bar")",
        "+	var hp_bar: ProgressBar = unit.get("hp_bar") as ProgressBar",
        "+	var shield_bg: ColorRect = unit.get("shield_bg") as ColorRect",
        "+	var shield_fill: ColorRect = unit.get("shield_fill") as ColorRect",
        "+	var label: Label = unit.get("label")",
        "+	if progress_bar:",
        "+		progress_bar.value = 0.0",
        "+	var tween := get_tree().create_tween()",
        "+	tween.set_pause_mode(Tween.TWEEN_PAUSE_PROCESS)",
        "+	if sprite:",
        "+		tween.tween_property(sprite, "modulate:a", 0.0, maxf(death_fade_time, 0.01))",
        "+	if progress_bar:",
        "+		tween.parallel().tween_property(progress_bar, "modulate:a", 0.0, maxf(death_fade_time, 0.01))",
        "+	if hp_bar:",
        "+		tween.parallel().tween_property(hp_bar, "modulate:a", 0.0, maxf(death_fade_time, 0.01))",
        "+	if shield_bg:",
        "+		tween.parallel().tween_property(shield_bg, "modulate:a", 0.0, maxf(death_fade_time, 0.01))",
        "+	if shield_fill:",
        "+		tween.parallel().tween_property(shield_fill, "modulate:a", 0.0, maxf(death_fade_time, 0.01))",
        "+	if label:",
        "+		tween.parallel().tween_property(label, "modulate:a", 0.0, maxf(death_fade_time, 0.01))",
        "+	if side == "worker":",
        "+		_worker_death_fades_pending += 1",
        "+	else:",
        "+		_enemy_death_fades_pending += 1",
        "+	tween.finished.connect(func() -> void:",
        "+		_on_unit_death_fade_finished(side)",
        "+	)",
        "+",
        "+func _remove_defeated_nodes() -> void:",
        "+	if _losing_side == "enemy":",
        "+		_award_enemy_defeat_gold()",
        "+		for node in _enemy_world_nodes:",
        "+			if node and is_instance_valid(node):",
        "+				if node.has_method("leave_defeated_body"):",
        "+					node.call("leave_defeated_body", true)",
        "+				else:",
        "+					node.queue_free()",
        "+		return",
        "+	if _losing_side == "worker":",
        "+		for node in _worker_world_nodes:",
        "+			if node and is_instance_valid(node):",
        "+				node.queue_free()",
        "+",
        "+",
        "+func _award_enemy_defeat_gold() -> void:",
        "+	if Engine.is_editor_hint() or GameEvents == null or not GameEvents.has_method("add_gold"):",
        "+		return",
        "+	var total_reward: float = 0.0",
        "+	for unit in _enemy_units:",
        "+		if int(unit.get("hp", 0)) > 0:",
        "+			continue",
        "+		var actor: BattleActor = unit.get("actor")",
        "+		if actor == null:",
        "+			continue",
        "+		total_reward += maxf(actor.defeat_gold_reward, 0.0)",
        "+	if total_reward <= 0.0:",
        "+		return",
        "+	GameEvents.add_gold(total_reward)",
        "+	var prompt: Node = get_tree().current_scene.get_node_or_null("CommonPrompt") if get_tree() != null and get_tree().current_scene != null else null",
        "+	if prompt != null and prompt.has_method("show_notice"):",
        "+		prompt.call("show_notice", "获得 %s。" % _format_reward_gold(total_reward), 1.1)",
        "+",
        "+",
        "+func _format_reward_gold(value: float) -> String:",
        "+	var rounded: float = snappedf(maxf(value, 0.0), 0.1)",
        "+	if is_equal_approx(rounded, round(rounded)):",
        "+		return "%d G" % int(round(rounded))",
        "+	return "%.1f G" % rounded",
        "+",
        "+func _ensure_battle_layer_visible() -> void:",
        "+	if _battle_layer:",
        "+		_battle_layer.show()",
        "+",
        "+func _hide_battle_layer() -> void:",
        "+	if _battle_layer:",
        "+		_battle_layer.hide()",
        "+",
        "+func _update_unit_ui(unit: Dictionary) -> void:",
        "+	var actor: BattleActor = unit.get("actor")",
        "+	var hp_bar: ProgressBar = unit.get("hp_bar") as ProgressBar",
        "+	var shield_bg: ColorRect = unit.get("shield_bg") as ColorRect",
        "+	var shield_fill: ColorRect = unit.get("shield_fill") as ColorRect",
        "+	var label: Label = unit.get("label")",
        "+	var progress_bar: ProgressBar = unit.get("progress_bar")",
        "+	if actor == null:",
        "+		return",
        "+	var max_hp: int = maxi(_get_unit_max_hp(actor, unit), 1)",
        "+	var hp_value: int = int(unit.get("hp", 0))",
        "+	var hp_ratio: float = clampf(float(hp_value) / float(max_hp), 0.0, 1.0)",
        "+	if hp_bar:",
        "+		hp_bar.value = hp_ratio",
        "+	if shield_bg != null and shield_fill != null:",
        "+		var has_shield: bool = int(unit.get("shield", 0)) > 0",
        "+		shield_bg.visible = has_shield",
        "+		shield_fill.visible = has_shield",
        "+	if label:",
        "+		var short_name: String = actor.display_name",
        "+		if short_name.length() > 10:",
        "+			short_name = short_name.substr(0, 10)",
        "+		label.text = "%s %d/%d" % [short_name, unit.get("hp", 0), max_hp]",
        "+		if int(unit.get("shield", 0)) > 0:",
        "+			label.text += " +%d" % int(unit.get("shield", 0))",
        "+	if progress_bar and unit.get("hp", 0) <= 0:",
        "+		progress_bar.value = 0.0",
        "+",
        "+",
        "+func _get_unit_max_hp(actor: BattleActor, unit: Dictionary) -> int:",
        "+	if actor == null:",
        "+		return 1",
        "+	return maxi(actor.max_hp, 1)",
        "+",
        "+",
        "+func _update_all_unit_ui() -> void:",
        "+	for unit in _worker_units:",
        "+		_update_unit_ui(unit)",
        "+	for unit in _enemy_units:",
        "+		_update_unit_ui(unit)",
        "+",
        "+func _reset_ghost_bars() -> void:",
        "+	_worker_ghosts_pending = 0",
        "+	_enemy_ghosts_pending = 0",
        "+	_worker_death_fades_pending = 0",
        "+	_enemy_death_fades_pending = 0",
        "+	_clear_ghosts("worker_hp_ghost")",
        "+	_clear_ghosts("enemy_hp_ghost")",
        "+",
        "+func _queue_finish(side: String) -> void:",
        "+	if _pending_finish:",
        "+		return",
        "+	_pending_finish = true",
        "+	_pending_finish_side = side",
        "+	_losing_side = side",
        "+	_try_finish_when_ready()",
        "+",
        "+func _spawn_hp_ghost(side: String, template: ProgressBar, prev_ratio: float) -> void:",
        "+	if template == null:",
        "+		return",
        "+	var ghost := template.duplicate()",
        "+	ghost.name = "%sGhost" % template.name",
        "+	ghost.fill_mode = template.fill_mode",
        "+	ghost.layout_direction = template.layout_direction",
        "+	ghost.value = prev_ratio",
        "+	ghost.modulate = hp_ghost_color",
        "+	ghost.visible = true",
        "+	ghost.show_percentage = false",
        "+	_promote_battle_ui_canvas_item(ghost, BATTLE_UI_GHOST_Z)",
        "+	ghost.add_to_group("%s_hp_ghost" % side)",
        "+	var ghost_parent := template.get_parent()",
        "+	if ghost_parent:",
        "+		ghost_parent.add_child(ghost)",
        "+	else:",
        "+		add_child(ghost)",
        "+	if side == "worker":",
        "+		_worker_ghosts_pending += 1",
        "+	else:",
        "+		_enemy_ghosts_pending += 1",
        "+	var tween := get_tree().create_tween()",
        "+	tween.set_pause_mode(Tween.TWEEN_PAUSE_PROCESS)",
        "+	tween.tween_property(ghost, "modulate:a", 0.0, maxf(hp_ghost_fade, 0.01)).set_delay(maxf(hp_ghost_hold, 0.0))",
        "+	tween.finished.connect(func():",
        "+		if ghost != null and is_instance_valid(ghost):",
        "+			ghost.queue_free()",
        "+		_on_ghost_finished(side)",
        "+	)",
        "+",
        "+func _on_ghost_finished(side: String) -> void:",
        "+	if side == "worker":",
        "+		_worker_ghosts_pending = max(_worker_ghosts_pending - 1, 0)",
        "+		_try_finish_when_ready()",
        "+		return",
        "+	_enemy_ghosts_pending = max(_enemy_ghosts_pending - 1, 0)",
        "+	_try_finish_when_ready()",
        "+",
        "+",
        "+func _on_unit_death_fade_finished(side: String) -> void:",
        "+	if side == "worker":",
        "+		_worker_death_fades_pending = max(_worker_death_fades_pending - 1, 0)",
        "+		_try_finish_when_ready()",
        "+		return",
        "+	_enemy_death_fades_pending = max(_enemy_death_fades_pending - 1, 0)",
        "+	_try_finish_when_ready()",
        "+",
        "+",
        "+func _try_finish_when_ready() -> void:",
        "+	if not _pending_finish:",
        "+		return",
        "+	if _pending_finish_side == "worker":",
        "+		if _worker_ghosts_pending == 0 and _worker_death_fades_pending == 0:",
        "+			_finish_battle()",
        "+		return",
        "+	if _pending_finish_side == "enemy":",
        "+		if _enemy_ghosts_pending == 0 and _enemy_death_fades_pending == 0:",
        "+			_finish_battle()",
        "+",
        "+",
        "+func _clear_ghosts(group_name: String) -> void:",
        "+	for node in get_tree().get_nodes_in_group(group_name):",
        "+		if node is Node:",
        "+			node.queue_free()",
        "+",
        "+func _hide_ui_templates() -> void:",
        "+	if _worker_bar_template:",
        "+		_worker_bar_template.hide()",
        "+	if _worker_hp_bar_template:",
        "+		_worker_hp_bar_template.hide()",
        "+	if _worker_ghost_template:",
        "+		_worker_ghost_template.hide()",
        "+	if _worker_hp_label_template:",
        "+		_worker_hp_label_template.hide()",
        "+	if _enemy_bar_template:",
        "+		_enemy_bar_template.hide()",
        "+	if _enemy_hp_bar_template:",
        "+		_enemy_hp_bar_template.hide()",
        "+	if _enemy_ghost_template:",
        "+		_enemy_ghost_template.hide()",
        "+	if _enemy_hp_label_template:",
        "+		_enemy_hp_label_template.hide()",
        "+",
        "+func _clear_dynamic_ui() -> void:",
        "+	for node in get_tree().get_nodes_in_group("battle_ui_dynamic"):",
        "+		if node is Node:",
        "+			node.queue_free()",
        "+	if _attack_aim_root != null and is_instance_valid(_attack_aim_root):",
        "+		for child in _attack_aim_root.get_children():",
        "+			if child is Node:",
        "+				(child as Node).queue_free()",
        "+	if _attack_fx_root != null and is_instance_valid(_attack_fx_root):",
        "+		for child in _attack_fx_root.get_children():",
        "+			if child is Node:",
        "+				(child as Node).queue_free()",
        "+	_clear_editor_anchor_gizmos()",
        "+",
        "+",
        "+func _force_hide_ui_templates() -> void:",
        "+	# Keep template bars hidden in editor so only generated preview bars are visible.",
        "+	if _worker_bar_template:",
        "+		_worker_bar_template.hide()",
        "+	if _worker_hp_bar_template:",
        "+		_worker_hp_bar_template.hide()",
        "+	if _worker_ghost_template:",
        "+		_worker_ghost_template.hide()",
        "+	if _worker_hp_label_template:",
        "+		_worker_hp_label_template.hide()",
        "+	if _enemy_bar_template:",
        "+		_enemy_bar_template.hide()",
        "+	if _enemy_hp_bar_template:",
        "+		_enemy_hp_bar_template.hide()",
        "+	if _enemy_ghost_template:",
        "+		_enemy_ghost_template.hide()",
        "+	if _enemy_hp_label_template:",
        "+		_enemy_hp_label_template.hide()",
        "+",
        "+func _build_worker_units() -> Array[Dictionary]:",
        "+	var units: Array[Dictionary] = []",
        "+	var extras: Array = []",
        "+	var party_source: Array = worker_party",
        "+	if not Engine.is_editor_hint() and GameEvents.has_method("get_worker_party"):",
        "+		party_source = GameEvents.get_worker_party()",
        "+	for actor in party_source:",
        "+		if actor == null:",
        "+			continue",
        "+		extras.append(actor)",
        "+		if extras.size() >= max(_desired_worker_count - 1, 0):",
        "+			break",
        "+	if units.size() < _desired_worker_count:",
        "+		var lead_actor: BattleActor = leader_actor",
        "+		if lead_actor == null and Engine.is_editor_hint():",
        "+			lead_actor = _make_preview_actor("Leader")",
        "+		if lead_actor:",
        "+			units.append(_create_unit(lead_actor, _leader_marker, "worker", 0))",
        "+	var slot_index := 0",
        "+	for actor in extras:",
        "+		if units.size() >= _desired_worker_count:",
        "+			break",
        "+		var marker := _ally_markers[slot_index] if slot_index < _ally_markers.size() else null",
        "+		units.append(_create_unit(actor, marker, "worker", units.size()))",
        "+		slot_index += 1",
        "+",
        "+	if Engine.is_editor_hint():",
        "+		while units.size() < _desired_worker_count:",
        "+			var marker := _ally_markers[slot_index] if slot_index < _ally_markers.size() else null",
        "+			if marker == null:",
        "+				break",
        "+			units.append(_create_unit(_make_preview_actor("Worker %d" % (units.size() + 1)), marker, "worker", units.size()))",
        "+			slot_index += 1",
        "+	return units",
        "+",
        "+func _build_enemy_units() -> Array[Dictionary]:",
        "+	var units: Array[Dictionary] = []",
        "+	var actors: Array = _get_enemy_battle_actors()",
        "+	var slot_index := 0",
        "+	for actor in actors:",
        "+		if actor == null:",
        "+			continue",
        "+		if slot_index >= _enemy_markers.size() or slot_index >= _desired_enemy_count:",
        "+			break",
        "+		var marker := _enemy_markers[slot_index]",
        "+		units.append(_create_unit(actor, marker, "enemy", slot_index))",
        "+		slot_index += 1",
        "+",
        "+	if Engine.is_editor_hint() and _battle_enemy_node == null:",
        "+		while units.size() < _desired_enemy_count and slot_index < _enemy_markers.size():",
        "+			var marker := _enemy_markers[slot_index]",
        "+			units.append(_create_unit(_make_preview_actor("Enemy %d" % (slot_index + 1)), marker, "enemy", slot_index))",
        "+			slot_index += 1",
        "+	return units",
        "+",
        "+func _apply_layouts() -> void:",
        "+	var worker_markers := _get_layout_markers(worker_layout_root, _worker_units.size(), false)",
        "+	if worker_markers.size() > 0:",
        "+		_apply_markers_to_units(_worker_units, worker_markers)",
        "+	else:",
        "+		_apply_layout_to_units(_worker_units, _get_worker_layout(_worker_units.size()))",
        "+	var enemy_markers := _get_layout_markers(enemy_layout_root, _enemy_units.size(), false)",
        "+	if enemy_markers.size() > 0:",
        "+		_apply_markers_to_units(_enemy_units, enemy_markers)",
        "+	else:",
        "+		_apply_layout_to_units(_enemy_units, _get_enemy_layout(_enemy_units.size()))",
        "+	_refresh_battle_unit_draw_order()",
        "+",
        "+func _apply_layout_to_units(units: Array, layout: PackedVector2Array) -> void:",
        "+	if layout.is_empty():",
        "+		return",
        "+	for i in range(min(units.size(), layout.size())):",
        "+		var marker: Marker2D = units[i].get("marker")",
        "+		if marker:",
        "+			marker.position = layout[i]",
        "+",
        "+func _apply_markers_to_units(units: Array, markers: Array[Marker2D]) -> void:",
        "+	for i in range(min(units.size(), markers.size())):",
        "+		units[i]["marker"] = markers[i]",
        "+",
        "+func _get_worker_layout(count: int) -> PackedVector2Array:",
        "+	var from_nodes := _get_layout_from_nodes(worker_layout_root, count, false)",
        "+	if not from_nodes.is_empty():",
        "+		return from_nodes",
        "+	match count:",
        "+		1:",
        "+			return worker_layout_1",
        "+		2:",
        "+			return worker_layout_2",
        "+		3:",
        "+			return worker_layout_3",
        "+		4:",
        "+			return worker_layout_4",
        "+		_:",
        "+			return worker_layout_4",
        "+",
        "+func _get_enemy_layout(count: int) -> PackedVector2Array:",
        "+	var from_nodes := _get_layout_from_nodes(enemy_layout_root, count, false)",
        "+	if not from_nodes.is_empty():",
        "+		return from_nodes",
        "+	match count:",
        "+		1:",
        "+			return enemy_layout_1",
        "+		2:",
        "+			return enemy_layout_2",
        "+		3:",
        "+			return enemy_layout_3",
        "+		4:",
        "+			return enemy_layout_4",
        "+		_:",
        "+			return enemy_layout_4",
        "+",
        "+func _get_desired_worker_count() -> int:",
        "+	if Engine.is_editor_hint():",
        "+		return clampi(preview_worker_count, 1, 4)",
        "+	var worker_count: int = 0",
        "+	if GameEvents.has_method("get_worker_party"):",
        "+		worker_count = GameEvents.get_worker_party().size()",
        "+	else:",
        "+		worker_count = worker_party.size()",
        "+	var leader_count: int = 1 if leader_actor != null else 0",
        "+	return clampi(leader_count + worker_count, 1, 4)",
        "+",
        "+",
        "+func _get_desired_enemy_count() -> int:",
        "+	if Engine.is_editor_hint() and _battle_enemy_node == null:",
        "+		return clampi(preview_enemy_count, 1, 4)",
        "+	var actors: Array = _get_enemy_battle_actors()",
        "+	var derived_count: int = actors.size()",
        "+	# When a world enemy explicitly provides its battle actors, that list is the",
        "+	# source of truth. The legacy metadata flag is only a fallback for old scenes.",
        "+	if derived_count > 0:",
        "+		return clampi(derived_count, 1, 4)",
        "+	if _battle_enemy_node != null and _battle_enemy_node.has_meta("battle_party_size"):",
        "+		var requested: int = clampi(int(_battle_enemy_node.get_meta("battle_party_size")), 1, 4)",
        "+		return requested",
        "+	return 1",
        "+",
        "+",
        "+func _get_enemy_battle_actors() -> Array:",
        "+	var actors: Array = []",
        "+	if _battle_enemy_node != null:",
        "+		var node_leader_v: Variant = _battle_enemy_node.get("battle_leader_actor")",
        "+		if node_leader_v is BattleActor:",
        "+			_append_unique_actor(actors, node_leader_v as BattleActor)",
        "+		elif enemy_actor != null:",
        "+			_append_unique_actor(actors, enemy_actor)",
        "+		var node_party_v: Variant = _battle_enemy_node.get("battle_extra_party")",
        "+		if node_party_v is Array:",
        "+			for a in node_party_v:",
        "+				if a is BattleActor:",
        "+					actors.append(a as BattleActor)",
        "+		return actors",
        "+",
        "+	var leader: BattleActor = enemy_actor",
        "+	if leader == null:",
        "+		if Engine.is_editor_hint():",
        "+			leader = _make_preview_actor("Enemy")",
        "+		else:",
        "+			var fallback := load("res://Resources/enemy_actor.tres")",
        "+			if fallback is BattleActor:",
        "+				leader = fallback",
        "+	_append_unique_actor(actors, leader)",
        "+",
        "+	var party_source: Array = enemy_party",
        "+	if not Engine.is_editor_hint() and GameEvents.has_method("get_enemy_party"):",
        "+		var global_party: Array = GameEvents.get_enemy_party()",
        "+		if global_party.size() > 0:",
        "+			party_source = global_party",
        "+	for actor in party_source:",
        "+		if actor is BattleActor:",
        "+			actors.append(actor as BattleActor)",
        "+	return actors",
        "+",
        "+",
        "+func _append_unique_actor(target: Array, actor: BattleActor) -> void:",
        "+	if actor == null:",
        "+		return",
        "+	if target.has(actor):",
        "+		return",
        "+	target.append(actor)",
        "+",
        "+func _get_layout_from_nodes(root_path: NodePath, count: int, leader_last: bool) -> PackedVector2Array:",
        "+	var root := get_node_or_null(root_path) as Node",
        "+	if root == null:",
        "+		return PackedVector2Array()",
        "+	var layout_node := root.get_node_or_null("Layout%d" % count)",
        "+	if layout_node == null:",
        "+		return PackedVector2Array()",
        "+	var names := _get_layout_marker_names(count, leader_last)",
        "+	var result: PackedVector2Array = PackedVector2Array()",
        "+	for name in names:",
        "+		var marker := layout_node.get_node_or_null(name) as Marker2D",
        "+		if marker:",
        "+			result.append(marker.position)",
        "+	return result",
        "+",
        "+func _get_layout_markers(root_path: NodePath, count: int, leader_last: bool) -> Array[Marker2D]:",
        "+	var root := get_node_or_null(root_path) as Node",
        "+	if root == null:",
        "+		return []",
        "+	var layout_node := root.get_node_or_null("Layout%d" % count)",
        "+	if layout_node == null:",
        "+		return []",
        "+	var names := _get_layout_marker_names(count, leader_last)",
        "+	var result: Array[Marker2D] = []",
        "+	for name in names:",
        "+		var marker := layout_node.get_node_or_null(name) as Marker2D",
        "+		if marker:",
        "+			result.append(marker)",
        "+	return result",
        "+",
        "+func _get_layout_marker_names(count: int, leader_last: bool) -> Array[String]:",
        "+	if leader_last:",
        "+		match count:",
        "+			1:",
        "+				return ["Marker4"]",
        "+			2:",
        "+				return ["Marker1", "Marker4"]",
        "+			3:",
        "+				return ["Marker1", "Marker2", "Marker4"]",
        "+			_:",
        "+				return ["Marker1", "Marker2", "Marker3", "Marker4"]",
        "+	match count:",
        "+		1:",
        "+			return ["Marker1"]",
        "+		2:",
        "+			return ["Marker1", "Marker2"]",
        "+		3:",
        "+			return ["Marker1", "Marker2", "Marker3"]",
        "+		_:",
        "+			return ["Marker1", "Marker2", "Marker3", "Marker4"]",
        "+",
        "+func _create_unit(actor: BattleActor, marker: Marker2D, side: String, index: int) -> Dictionary:",
        "+	var max_hp_value: int = maxi(actor.max_hp, 1) if actor else 1",
        "+	var current_hp_value: int = max_hp_value",
        "+	if side == "worker" and not Engine.is_editor_hint() and actor != null and GameEvents.has_method("get_actor_state"):",
        "+		var state: Dictionary = GameEvents.get_actor_state(actor)",
        "+		if not state.is_empty():",
        "+			max_hp_value = maxi(int(state.get("max_hp", max_hp_value)), 1)",
        "+			current_hp_value = clampi(int(state.get("hp", max_hp_value)), 0, max_hp_value)",
        "+	var unit: Dictionary = {",
        "+		"uid": _next_battle_unit_uid,",
        "+		"actor": actor,",
        "+		"hp": current_hp_value,",
        "+		"max_hp": max_hp_value,",
        "+		"shield": 0,",
        "+		"progress": 0.0,",
        "+		"side": side,",
        "+		"index": index,",
        "+		"marker": marker,",
        "+		"view": null,",
        "+		"sprite": null,",
        "+		"aim_marker": null,",
        "+		"aim_has_target": false,",
        "+		"aim_target_uid": -1,",
        "+		"aim_orbit_angle": 0.0,",
        "+		"aim_orbit_dir": 1.0,",
        "+		"aim_orbit_radius_x": 0.0,",
        "+		"aim_orbit_radius_y": 0.0,",
        "+		"temp_buffs": {",
        "+			"speed_boost_percent": 0.0,",
        "+			"damage_boost_percent": 0.0,",
        "+			"hp_cost_percent": 0.0,",
        "+			"dodge_radius_percent": 0.0,",
        "+			"stack_count": 0",
        "+		},",
        "+		"encouragement_debug_count": 0,",
        "+		"hurtbox_area": null,",
        "+		"hurtbox_shape": null,",
        "+		"hurtbox_shapes": [],",
        "+		"progress_bar": null,",
        "+		"hp_bar": null,",
        "+		"shield_bg": null,",
        "+		"shield_fill": null,",
        "+		"label": null,",
        "+		"status": "down" if current_hp_value <= 0 else "alive"",
        "+	}",
        "+	_next_battle_unit_uid += 1",
        "+	var bar_template := _worker_bar_template if side == "worker" else _enemy_bar_template",
        "+	var hp_template := _worker_hp_bar_template if side == "worker" else _enemy_hp_bar_template",
        "+	var label_template := _worker_hp_label_template if side == "worker" else _enemy_hp_label_template",
        "+	var ui_rect := _get_hp_ui_rect(side, index)",
        "+	var ui_rect_progress := ui_rect",
        "+	var ui_rect_hp := ui_rect",
        "+	if hp_overhead_mode and marker != null:",
        "+		var overhead := _get_overhead_ui_rects(unit, bar_template)",
        "+		ui_rect_progress = overhead.get("progress_rect", ui_rect)",
        "+		ui_rect_hp = overhead.get("hp_rect", ui_rect)",
        "+	if bar_template:",
        "+		var bar := _duplicate_bar(bar_template, "%sBar%d" % [side, index], ui_rect_progress)",
        "+		bar.value = 0.0",
        "+		unit["progress_bar"] = bar",
        "+	if hp_template:",
        "+		var hp_bar := _duplicate_bar(hp_template, "%sHpBar%d" % [side, index], ui_rect_hp)",
        "+		hp_bar.value = 1.0",
        "+		unit["hp_bar"] = hp_bar",
        "+		var shield_rects: Dictionary = _create_shield_colorrects(hp_bar, side, index)",
        "+		unit["shield_bg"] = shield_rects.get("bg") as ColorRect",
        "+		unit["shield_fill"] = shield_rects.get("fill") as ColorRect",
        "+	if show_hp_labels and label_template:",
        "+		var label := _duplicate_label(label_template, "%sHpLabel%d" % [side, index], ui_rect)",
        "+		unit["label"] = label",
        "+",
        "+	if current_hp_value <= 0:",
        "+		var progress_bar: ProgressBar = unit.get("progress_bar")",
        "+		if progress_bar:",
        "+			progress_bar.value = 0.0",
        "+			progress_bar.modulate.a = 0.0",
        "+		var hp_bar: ProgressBar = unit.get("hp_bar") as ProgressBar",
        "+		if hp_bar:",
        "+			hp_bar.value = 0.0",
        "+			hp_bar.modulate.a = 0.0",
        "+		var s_bg: ColorRect = unit.get("shield_bg") as ColorRect",
        "+		if s_bg:",
        "+			s_bg.visible = false",
        "+		var s_fill: ColorRect = unit.get("shield_fill") as ColorRect",
        "+		if s_fill:",
        "+			s_fill.visible = false",
        "+		var hp_label: Label = unit.get("label")",
        "+		if hp_label:",
        "+			hp_label.modulate.a = 0.0",
        "+",
        "+	return unit",
        "+",
        "+",
        "+func _disable_unit_hurtbox(unit: Dictionary) -> void:",
        "+	for hurtbox_shape in _get_unit_hurtbox_shapes(unit):",
        "+		if hurtbox_shape != null:",
        "+			hurtbox_shape.disabled = true",
        "+	var hurtbox_area: Area2D = unit.get("hurtbox_area", null) as Area2D",
        "+	if hurtbox_area != null:",
        "+		hurtbox_area.monitoring = false",
        "+		hurtbox_area.monitorable = false",
        "+",
        "+",
        "+func _get_unit_hurtbox_shapes(unit: Dictionary) -> Array[CollisionShape2D]:",
        "+	var result: Array[CollisionShape2D] = []",
        "+	var hurtbox_shapes_v: Variant = unit.get("hurtbox_shapes", [])",
        "+	if hurtbox_shapes_v is Array:",
        "+		for shape_v in hurtbox_shapes_v:",
        "+			var shape_node: CollisionShape2D = shape_v as CollisionShape2D",
        "+			if shape_node != null and is_instance_valid(shape_node):",
        "+				result.append(shape_node)",
        "+	if not result.is_empty():",
        "+		return result",
        "+	var single_shape: CollisionShape2D = unit.get("hurtbox_shape", null) as CollisionShape2D",
        "+	if single_shape != null and is_instance_valid(single_shape):",
        "+		result.append(single_shape)",
        "+	return result",
        "+",
        "+",
        "+func _shape_to_target_space_rect(shape_node: CollisionShape2D) -> Rect2:",
        "+	if shape_node == null or shape_node.disabled or shape_node.shape == null:",
        "+		return Rect2()",
        "+	var points: PackedVector2Array = _get_shape_local_points(shape_node.shape)",
        "+	if points.is_empty():",
        "+		return Rect2()",
        "+	var first_point: Vector2 = shape_node.global_transform * points[0]",
        "+	if _attack_fx_root != null and is_instance_valid(_attack_fx_root):",
        "+		first_point = _attack_fx_root.to_local(first_point)",
        "+	var min_point: Vector2 = first_point",
        "+	var max_point: Vector2 = first_point",
        "+	for i in range(1, points.size()):",
        "+		var transformed: Vector2 = shape_node.global_transform * points[i]",
        "+		if _attack_fx_root != null and is_instance_valid(_attack_fx_root):",
        "+			transformed = _attack_fx_root.to_local(transformed)",
        "+		min_point.x = minf(min_point.x, transformed.x)",
        "+		min_point.y = minf(min_point.y, transformed.y)",
        "+		max_point.x = maxf(max_point.x, transformed.x)",
        "+		max_point.y = maxf(max_point.y, transformed.y)",
        "+	return Rect2(min_point, max_point - min_point)",
        "+",
        "+",
        "+func _get_shape_local_points(shape: Shape2D) -> PackedVector2Array:",
        "+	if shape == null:",
        "+		return PackedVector2Array()",
        "+	if shape is RectangleShape2D:",
        "+		var rect_shape: RectangleShape2D = shape as RectangleShape2D",
        "+		var half_size: Vector2 = rect_shape.size * 0.5",
        "+		return PackedVector2Array([",
        "+			Vector2(-half_size.x, -half_size.y),",
        "+			Vector2(half_size.x, -half_size.y),",
        "+			Vector2(half_size.x, half_size.y),",
        "+			Vector2(-half_size.x, half_size.y),",
        "+		])",
        "+	if shape is ConvexPolygonShape2D:",
        "+		return (shape as ConvexPolygonShape2D).points",
        "+	if shape is ConcavePolygonShape2D:",
        "+		return (shape as ConcavePolygonShape2D).segments",
        "+	if shape is CircleShape2D:",
        "+		var circle_shape: CircleShape2D = shape as CircleShape2D",
        "+		var radius: float = circle_shape.radius",
        "+		return PackedVector2Array([",
        "+			Vector2(-radius, -radius),",
        "+			Vector2(radius, -radius),",
        "+			Vector2(radius, radius),",
        "+			Vector2(-radius, radius),",
        "+		])",
        "+	if shape is CapsuleShape2D:",
        "+		var capsule_shape: CapsuleShape2D = shape as CapsuleShape2D",
        "+		var half_height: float = maxf(capsule_shape.height * 0.5, capsule_shape.radius)",
        "+		var radius: float = capsule_shape.radius",
        "+		return PackedVector2Array([",
        "+			Vector2(-radius, -half_height),",
        "+			Vector2(radius, -half_height),",
        "+			Vector2(radius, half_height),",
        "+			Vector2(-radius, half_height),",
        "+		])",
        "+	return PackedVector2Array()",
        "+",
        "+",
        "+func _get_actor_battle_frame_size(actor: BattleActor) -> Vector2:",
        "+	if actor == null or actor.portrait_texture == null:",
        "+		return Vector2(32.0, 32.0)",
        "+	if actor.battle_use_sheet:",
        "+		return Vector2(",
        "+			maxf(actor.portrait_texture.get_width() / float(max(actor.battle_sheet_hframes, 1)), 1.0),",
        "+			maxf(actor.portrait_texture.get_height() / float(max(actor.battle_sheet_vframes, 1)), 1.0)",
        "+		)",
        "+	return actor.portrait_texture.get_size()",
        "+",
        "+",
        "+func _get_hp_ui_rect(side: String, index: int) -> Rect2:",
        "+	var template := _worker_bar_template if side == "worker" else _enemy_bar_template",
        "+	if template == null:",
        "+		return Rect2(0.0, 0.0, 120.0, 0.0)",
        "+",
        "+	if not hp_ui_horizontal:",
        "+		return Rect2(template.offset_left, party_row_spacing * float(index), template.offset_right - template.offset_left, 0.0)",
        "+",
        "+	var viewport_w: float = battle_box_size.x if battle_box_size.x > 0.0 else 640.0",
        "+	var mid_x: float = viewport_w * 0.5",
        "+	var side_min: float = hp_ui_edge_margin",
        "+	var side_max: float = mid_x - hp_ui_center_gap",
        "+	var count: int = max(_desired_worker_count, 1)",
        "+	if side == "enemy":",
        "+		side_min = mid_x + hp_ui_center_gap",
        "+		side_max = viewport_w - hp_ui_edge_margin",
        "+		count = max(_desired_enemy_count, 1)",
        "+",
        "+	var template_width: float = template.offset_right - template.offset_left",
        "+	var available_w: float = maxf(side_max - side_min, 1.0)",
        "+	var gap: float = maxf(hp_ui_min_spacing, 0.0)",
        "+	if count > 1:",
        "+		var min_slot_for_gap := (available_w - gap * float(count - 1)) / float(count)",
        "+		if min_slot_for_gap < hp_ui_min_slot_width:",
        "+			gap = maxf((available_w - hp_ui_min_slot_width * float(count)) / float(count - 1), 2.0)",
        "+",
        "+	var slot_w := (available_w - gap * float(max(count - 1, 0))) / float(max(count, 1))",
        "+	slot_w = clampf(slot_w, 36.0, template_width)",
        "+",
        "+	var left := side_min + float(index) * (slot_w + gap)",
        "+	left = clampf(left, side_min, side_max - slot_w)",
        "+	return Rect2(left, 0.0, slot_w, 0.0)",
        "+",
        "+",
        "+func _create_shield_colorrects(hp_bar: ProgressBar, side: String, index: int) -> Dictionary:",
        "+	# 护盾条用两个 ColorRect 实现：bg（全宽背景）+ fill（按比例填充）",
        "+	# 直接作为 hp_bar 的兄弟节点添加到同一父节点，z_index 高于 hp_bar",
        "+	var parent := hp_bar.get_parent()",
        "+	if parent == null:",
        "+		return {}",
        "+	var h: float = maxf((hp_bar.offset_bottom - hp_bar.offset_top) * clampf(shield_bar_height_ratio, 0.1, 1.0), 1.0)",
        "+	var x: float = hp_bar.offset_left",
        "+	var y: float = hp_bar.offset_top",
        "+	var w: float = hp_bar.offset_right - hp_bar.offset_left",
        "+",
        "+	var bg := ColorRect.new()",
        "+	bg.name = "%sShieldBg%d" % [side, index]",
        "+	bg.color = Color(0.0, 0.0, 0.0, 0.0)",
        "+	bg.mouse_filter = Control.MOUSE_FILTER_IGNORE",
        "+	_promote_battle_ui_canvas_item(bg, BATTLE_UI_SHIELD_BG_Z)",
        "+	bg.layout_mode = 0",
        "+	bg.offset_left = x",
        "+	bg.offset_top = y",
        "+	bg.offset_right = x + w",
        "+	bg.offset_bottom = y + h",
        "+	bg.visible = false",
        "+	bg.add_to_group("battle_ui_dynamic")",
        "+	parent.add_child(bg)",
        "+",
        "+	var fill := ColorRect.new()",
        "+	fill.name = "%sShieldFill%d" % [side, index]",
        "+	fill.color = shield_bar_color",
        "+	fill.mouse_filter = Control.MOUSE_FILTER_IGNORE",
        "+	_promote_battle_ui_canvas_item(fill, BATTLE_UI_SHIELD_FILL_Z)",
        "+	fill.layout_mode = 0",
        "+	fill.offset_left = x",
        "+	fill.offset_top = y",
        "+	fill.offset_right = x  # 初始宽度为0",
        "+	fill.offset_bottom = y + h",
        "+	fill.visible = false",
        "+	fill.add_to_group("battle_ui_dynamic")",
        "+	parent.add_child(fill)",
        "+",
        "+	return {"bg": bg, "fill": fill}",
        "+",
        "+func _duplicate_bar(template: ProgressBar, name: String, ui_rect: Rect2) -> ProgressBar:",
        "+	var bar := template.duplicate()",
        "+	bar.name = name",
        "+	bar.visible = true",
        "+	bar.layout_mode = template.layout_mode",
        "+	bar.anchor_left = template.anchor_left",
        "+	bar.anchor_top = template.anchor_top",
        "+	bar.anchor_right = template.anchor_right",
        "+	bar.anchor_bottom = template.anchor_bottom",
        "+	var template_h := template.offset_bottom - template.offset_top",
        "+	var h := ui_rect.size.y if ui_rect.size.y > 0.0 else template_h",
        "+	bar.offset_left = ui_rect.position.x",
        "+	bar.offset_top = ui_rect.position.y",
        "+	bar.offset_right = ui_rect.position.x + ui_rect.size.x",
        "+	bar.offset_bottom = ui_rect.position.y + h",
        "+	bar.custom_minimum_size = template.custom_minimum_size",
        "+	bar.size_flags_horizontal = template.size_flags_horizontal",
        "+	bar.size_flags_vertical = template.size_flags_vertical",
        "+	bar.pivot_offset = template.pivot_offset",
        "+	bar.min_value = 0.0",
        "+	bar.max_value = 1.0",
        "+	bar.show_percentage = false",
        "+	_promote_battle_ui_canvas_item(bar, BATTLE_UI_BAR_Z)",
        "+	bar.add_to_group("battle_ui_dynamic")",
        "+	var parent := template.get_parent()",
        "+	if parent:",
        "+		parent.add_child(bar)",
        "+	else:",
        "+		add_child(bar)",
        "+	return bar",
        "+",
        "+",
        "+func _get_overhead_ui_rects(unit: Dictionary, template: ProgressBar) -> Dictionary:",
        "+	var marker := unit.get("marker") as Marker2D",
        "+	if marker == null:",
        "+		return {}",
        "+",
        "+	var ui_parent := template.get_parent() as CanvasItem",
        "+	if ui_parent == null:",
        "+		return {}",
        "+",
        "+	var head_pos := _get_unit_head_ui_position(marker, ui_parent)",
        "+	var actor := unit.get("actor") as BattleActor",
        "+	var max_hp: int = maxi(int(unit.get("max_hp", 0)), 1)",
        "+	if max_hp <= 1 and actor != null:",
        "+		max_hp = maxi(actor.max_hp, 1)",
        "+",
        "+	# 宽度随 max_hp 对数缩放，边际收敛，以 hp_overhead_max_hp_reference 为基准",
        "+	# scale = log2(max_hp / ref + 1) / log2(2) = log2(ratio + 1)",
        "+	# ratio=1 时 scale=1（基准宽度），ratio 越大增长越慢",
        "+	var ref_hp: float = maxf(hp_overhead_max_hp_reference, 1.0)",
        "+	var ratio: float = float(max_hp) / ref_hp",
        "+	var hp_scale: float = log(ratio + 1.0) / log(2.0)  # log2(ratio+1)，ratio=1时=1",
        "+	var width: float = clampf(hp_overhead_width * hp_scale, hp_overhead_width_min, hp_overhead_width_max)",
        "+",
        "+	var side: String = String(unit.get("side", "worker"))",
        "+	var index: int = int(unit.get("index", 0))",
        "+	var slot_offset: Vector2 = _get_overhead_slot_offset(side, index)",
        "+	var actor_offset: Vector2 = actor.overhead_hp_offset if actor != null else Vector2.ZERO",
        "+",
        "+	var x: float = head_pos.x - width * 0.5 + slot_offset.x + actor_offset.x",
        "+	var base_y: float = head_pos.y + hp_overhead_y_offset + slot_offset.y + actor_offset.y",
        "+	var progress_h: float = maxf(hp_overhead_progress_height, 1.0)",
        "+	var hp_h: float = maxf(hp_overhead_hp_height, 1.0)",
        "+	var gap: float = maxf(hp_overhead_bar_gap, 0.0)",
        "+",
        "+	var progress_rect := Rect2(x, base_y, width, progress_h)",
        "+	var hp_rect := Rect2(x, base_y + progress_h + gap, width, hp_h)",
        "+	return {",
        "+		"progress_rect": progress_rect,",
        "+		"hp_rect": hp_rect,",
        "+		"bar_width": width,",
        "+	}",
        "+",
        "+",
        "+func _get_unit_head_ui_position(marker: Marker2D, ui_parent: CanvasItem) -> Vector2:",
        "+	# In this scene the markers (Node2D) and HP bars (Control) live under the same",
        "+	# battle root. Using global_position delta is the most stable in editor preview.",
        "+	var marker_global: Vector2 = marker.global_position",
        "+	var parent_global: Vector2 = ui_parent.global_position",
        "+	return marker_global - parent_global",
        "+",
        "+",
        "+func _update_overhead_ui_positions() -> void:",
        "+	_update_overhead_for_units(_worker_units)",
        "+	_update_overhead_for_units(_enemy_units)",
        "+",
        "+",
        "+func _update_overhead_for_units(units: Array) -> void:",
        "+	for unit in units:",
        "+		var marker := unit.get("marker") as Marker2D",
        "+		var bar := unit.get("progress_bar") as ProgressBar",
        "+		var hp_bar: ProgressBar = unit.get("hp_bar") as ProgressBar",
        "+		if marker == null or bar == null or hp_bar == null:",
        "+			continue",
        "+",
        "+		var overhead := _get_overhead_ui_rects(unit, bar)",
        "+		var progress_rect: Rect2 = overhead.get("progress_rect", Rect2())",
        "+		var hp_rect: Rect2 = overhead.get("hp_rect", Rect2())",
        "+",
        "+		_set_control_rect(bar, progress_rect)",
        "+		_set_control_rect(hp_bar, hp_rect)",
        "+",
        "+		# 护盾条跟随血条位置，高度按比例缩小",
        "+		# 宽度相对血条宽度，按护盾/max_hp比例缩放",
        "+		var shield_bg: ColorRect = unit.get("shield_bg") as ColorRect",
        "+		var shield_fill: ColorRect = unit.get("shield_fill") as ColorRect",
        "+		if shield_bg != null and shield_fill != null:",
        "+			var sh: float = maxf(hp_rect.size.y * clampf(shield_bar_height_ratio, 0.1, 1.0), 1.0)",
        "+			var shield_val: int = maxi(int(unit.get("shield", 0)), 0)",
        "+			var max_hp_val: int = maxi(int(unit.get("max_hp", 1)), 1)",
        "+			# 护盾条宽度 = 血条宽度 × (shield / maxHP)，可超过血条，但不超过 max_width",
        "+			var hp_bar_width: float = hp_rect.size.x",
        "+			var shield_ratio: float = float(shield_val) / float(max_hp_val)",
        "+			var shield_w: float = clampf(hp_bar_width * shield_ratio, 0.0, hp_overhead_width_max)",
        "+			shield_bg.offset_left = hp_rect.position.x",
        "+			shield_bg.offset_top = hp_rect.position.y",
        "+			shield_bg.offset_right = hp_rect.position.x + shield_w",
        "+			shield_bg.offset_bottom = hp_rect.position.y + sh",
        "+			shield_fill.offset_left = hp_rect.position.x",
        "+			shield_fill.offset_top = hp_rect.position.y",
        "+			shield_fill.offset_right = hp_rect.position.x + shield_w",
        "+			shield_fill.offset_bottom = hp_rect.position.y + sh",
        "+",
        "+		var label := unit.get("label") as Label",
        "+		if label != null:",
        "+			_set_control_rect(label, Rect2(progress_rect.position.x, progress_rect.position.y - 14.0, progress_rect.size.x, 12.0))",
        "+",
        "+",
        "+func _get_overhead_slot_offset(side: String, index: int) -> Vector2:",
        "+	var arr: PackedVector2Array = worker_overhead_slot_offsets if side == "worker" else enemy_overhead_slot_offsets",
        "+	if index >= 0 and index < arr.size():",
        "+		return arr[index]",
        "+	return Vector2.ZERO",
        "+",
        "+",
        "+func _set_control_rect(control: Control, rect: Rect2) -> void:",
        "+	if control == null:",
        "+		return",
        "+	control.offset_left = rect.position.x",
        "+	control.offset_top = rect.position.y",
        "+	control.offset_right = rect.position.x + rect.size.x",
        "+	control.offset_bottom = rect.position.y + rect.size.y",
        "+",
        "+",
        "+func _promote_battle_ui_canvas_item(item: CanvasItem, absolute_z_index: int) -> void:",
        "+	if item == null:",
        "+		return",
        "+	item.z_as_relative = false",
        "+	item.z_index = absolute_z_index",
        "+",
        "+",
        "+func _make_preview_actor(name: String) -> BattleActor:",
        "+	var actor := BattleActor.new()",
        "+	actor.display_name = name",
        "+	actor.max_hp = 20",
        "+	actor.max_mp = 15",
        "+	actor.damage = 1",
        "+	actor.attack_time = 1.0",
        "+	actor.attack_speed_multiplier = 1.0",
        "+	return actor",
        "+",
        "+",
        "+func _update_editor_anchor_gizmos() -> void:",
        "+	_clear_editor_anchor_gizmos()",
        "+	for unit in _worker_units:",
        "+		_add_editor_anchor_gizmo(unit, preview_worker_anchor_color)",
        "+	for unit in _enemy_units:",
        "+		_add_editor_anchor_gizmo(unit, preview_enemy_anchor_color)",
        "+",
        "+",
        "+func _add_editor_anchor_gizmo(unit: Dictionary, color: Color) -> void:",
        "+	var marker := unit.get("marker") as Marker2D",
        "+	var bar := unit.get("progress_bar") as ProgressBar",
        "+	if marker == null or bar == null:",
        "+		return",
        "+	var ui_parent := bar.get_parent() as CanvasItem",
        "+	if ui_parent == null:",
        "+		return",
        "+",
        "+	var head_pos: Vector2 = _get_unit_head_ui_position(marker, ui_parent)",
        "+	var half: float = maxf(preview_anchor_size * 0.5, 1.0)",
        "+",
        "+	var h := ColorRect.new()",
        "+	h.color = color",
        "+	h.mouse_filter = Control.MOUSE_FILTER_IGNORE",
        "+	_promote_battle_ui_canvas_item(h, BATTLE_UI_PREVIEW_GIZMO_Z)",
        "+	h.offset_left = head_pos.x - half",
        "+	h.offset_top = head_pos.y - 1.0",
        "+	h.offset_right = head_pos.x + half",
        "+	h.offset_bottom = head_pos.y + 1.0",
        "+	h.add_to_group("battle_ui_preview_anchor")",
        "+	ui_parent.add_child(h)",
        "+",
        "+	var v := ColorRect.new()",
        "+	v.color = color",
        "+	v.mouse_filter = Control.MOUSE_FILTER_IGNORE",
        "+	_promote_battle_ui_canvas_item(v, BATTLE_UI_PREVIEW_GIZMO_Z)",
        "+	v.offset_left = head_pos.x - 1.0",
        "+	v.offset_top = head_pos.y - half",
        "+	v.offset_right = head_pos.x + 1.0",
        "+	v.offset_bottom = head_pos.y + half",
        "+	v.add_to_group("battle_ui_preview_anchor")",
        "+	ui_parent.add_child(v)",
        "+",
        "+",
        "+func _clear_editor_anchor_gizmos() -> void:",
        "+	for node in get_tree().get_nodes_in_group("battle_ui_preview_anchor"):",
        "+		if node is Node:",
        "+			node.queue_free()",
        "+",
        "+func _duplicate_label(template: Label, name: String, ui_rect: Rect2) -> Label:",
        "+	var label := template.duplicate()",
        "+	label.name = name",
        "+	label.visible = true",
        "+	label.layout_mode = template.layout_mode",
        "+	label.anchor_left = template.anchor_left",
        "+	label.anchor_top = template.anchor_top",
        "+	label.anchor_right = template.anchor_right",
        "+	label.anchor_bottom = template.anchor_bottom",
        "+	var h := template.offset_bottom - template.offset_top",
        "+	label.offset_left = ui_rect.position.x",
        "+	label.offset_top = template.offset_top + ui_rect.position.y",
        "+	label.offset_right = ui_rect.position.x + ui_rect.size.x",
        "+	label.offset_bottom = template.offset_top + ui_rect.position.y + h",
        "+	label.horizontal_alignment = HORIZONTAL_ALIGNMENT_CENTER",
        "+	label.clip_text = true",
        "+	label.custom_minimum_size = template.custom_minimum_size",
        "+	label.size_flags_horizontal = template.size_flags_horizontal",
        "+	label.size_flags_vertical = template.size_flags_vertical",
        "+	label.pivot_offset = template.pivot_offset",
        "+	_promote_battle_ui_canvas_item(label, BATTLE_UI_LABEL_Z)",
        "+	label.add_to_group("battle_ui_dynamic")",
        "+	var parent := template.get_parent()",
        "+	if parent:",
        "+		parent.add_child(label)",
        "+	else:",
        "+		add_child(label)",
        "+	return label",
        "+",
        "+func _build_worker_world_nodes() -> Array[Node]:",
        "+	var nodes: Array[Node] = []",
        "+	var leader_node := get_node_or_null(leader_world_path)",
        "+	if leader_node:",
        "+		nodes.append(leader_node)",
        "+	var extras_count: int = max(_worker_units.size() - (1 if leader_actor else 0), 0)",
        "+	for i in range(min(worker_world_paths.size(), extras_count)):",
        "+		var path := worker_world_paths[i]",
        "+		var node := get_node_or_null(path)",
        "+		if node:",
        "+			nodes.append(node)",
        "+	return nodes",
        "+",
        "+func _build_enemy_world_nodes() -> Array[Node]:",
        "+	var nodes: Array[Node] = []",
        "+	if _battle_enemy_node:",
        "+		nodes.append(_battle_enemy_node)",
        "+	var extras_count: int = max(_enemy_units.size() - (1 if _battle_enemy_node else 0), 0)",
        "+	for i in range(min(enemy_world_paths.size(), extras_count)):",
        "+		var path := enemy_world_paths[i]",
        "+		var node := get_node_or_null(path)",
        "+		if node:",
        "+			nodes.append(node)",
        "+	return nodes"
      ]
    }
